INSERT INTO `categories` VALUES (1,NULL,'Drone Components','drone-components',1,1,1,'2026-07-21 13:02:54','2026-07-21 13:02:54'),(2,1,'Electronics','electronics',2,1,1,'2026-07-21 13:02:54','2026-07-21 13:02:54'),(3,2,'Flight Controllers','flight-controllers',3,1,1,'2026-07-21 13:02:54','2026-07-21 13:02:54'),(4,2,'Edge Compute','edge-compute',4,1,1,'2026-07-21 13:02:54','2026-07-21 13:02:54'),(5,2,'GNSS & Navigation','gnss-navigation',5,1,1,'2026-07-21 13:02:54','2026-07-21 13:02:54'),(6,2,'Sensors','sensors',6,1,1,'2026-07-21 13:02:54','2026-07-21 13:02:54'),(7,2,'Power & Servo','power-servo',7,1,1,'2026-07-21 13:02:54','2026-07-21 13:02:54'),(8,1,'Cameras','cameras',8,1,1,'2026-07-21 13:02:55','2026-07-21 13:02:55');
/*!40000 ALTER TABLE `categories` ENABLE KEYS */;
