DROP TABLE IF EXISTS `category_page_closings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `category_page_closings` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `category_page_id` bigint unsigned NOT NULL,
  `position` int unsigned NOT NULL,
  `variant` varchar(16) NOT NULL,
  `data` json NOT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_category_page_closings_page_position` (`category_page_id`,`position`),
  CONSTRAINT `fk_category_page_closings_page` FOREIGN KEY (`category_page_id`) REFERENCES `category_pages` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `chk_category_page_closings_variant` CHECK ((`variant` in (_utf8mb4'imageBand',_utf8mb4'simpleCta',_utf8mb4'govCta')))
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='Ordered closing CTA band(s) for a category_pages row (0, 1, or 2+ — Drone Components has two: imageBand then simpleCta, AC-21).';
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `category_page_closings` WRITE;
/*!40000 ALTER TABLE `category_page_closings` DISABLE KEYS */;
INSERT INTO `category_page_closings` VALUES (1,1,1,'imageBand','{\"alt\": \"CAN bus backbone connecting AAD avionics modules\", \"body\": \"One CAN backbone carries power and data across the whole stack. Each module is fault-isolated, Ardupilot-compatible, and built so a single failure never cascades into many.\", \"image\": \"/img/categories/drone-components/can-band.jpg\", \"title\": \"Every Module Speaks the Same Language\"}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(2,1,2,'simpleCta','{\"text\": \"Tell us your platform and mission profile — we\'ll map the flight control, compute, navigation, and power modules that fit, all on one bus.\", \"button\": {\"to\": \"/contacts\", \"label\": \"notify us\"}, \"heading\": \"Spec Your Avionics Stack\"}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(3,3,1,'govCta','{\"text\": \"Products on this page may be USML-controlled (ITAR) or EAR-controlled depending on configuration; sales are restricted to authorized buyers. For specifications, MIL-STD posture, NSN assignments where issued, GSA pricing under Contract GS-00F-000EX, or a capability briefing, contact AAD Government Sales.\", \"buttons\": [{\"to\": \"/contacts\", \"label\": \"Request a Capability Briefing\"}, {\"to\": \"mailto:gov@aerodefences.example\", \"label\": \"gov@aerodefences.example\"}], \"heading\": \"Export-Controlled · Government Channel\"}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(4,4,1,'govCta','{\"text\": \"Government-channel products differ from commercial variants, and detailed specifications are restricted to authorized buyers. For tube grades, FOM levels, MIL-STD posture, NSN assignment, current configurations, or a capability briefing, contact AAD Government Sales.\", \"buttons\": [{\"to\": \"/contacts\", \"label\": \"Request a Capability Briefing\"}, {\"to\": \"mailto:gov@aerodefences.example\", \"label\": \"gov@aerodefences.example\"}], \"heading\": \"Government-Channel Configurations\"}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(5,5,1,'simpleCta','{\"text\": \"Tell us your platform class, mission profile, and integration constraints — we\'ll match the cameras and electronics to the task.\", \"button\": {\"to\": \"/contacts\", \"label\": \"notify us\"}, \"heading\": \"Spec the Components for Your Platform\"}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(6,6,1,'simpleCta','{\"text\": \"Tell us your mission profile and target set — we\'ll scope the perception models, datasets, and autonomy software to match.\", \"button\": {\"to\": \"/contact\", \"label\": \"notify us\"}, \"heading\": \"Put Autonomy on Your Platform\"}','2026-07-21 13:02:56','2026-07-21 13:02:56');
/*!40000 ALTER TABLE `category_page_closings` ENABLE KEYS */;
UNLOCK TABLES;
DROP TABLE IF EXISTS `category_page_sections`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `category_page_sections` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `category_page_id` bigint unsigned NOT NULL,
  `position` int unsigned NOT NULL,
  `type` varchar(32) NOT NULL,
  `anchor` varchar(64) DEFAULT NULL,
  `head_eyebrow` varchar(255) DEFAULT NULL,
  `head_title` varchar(255) DEFAULT NULL,
  `head_lead` text,
  `data` json NOT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_category_page_sections_page_position` (`category_page_id`,`position`),
  CONSTRAINT `fk_category_page_sections_page` FOREIGN KEY (`category_page_id`) REFERENCES `category_pages` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `chk_category_page_sections_type` CHECK ((`type` in (_utf8mb4'deviceGrid',_utf8mb4'featureSplit',_utf8mb4'productRows',_utf8mb4'comparison',_utf8mb4'valueGrid',_utf8mb4'explainer',_utf8mb4'diagramBand',_utf8mb4'trustBar',_utf8mb4'categoryBlocks',_utf8mb4'problemSolution',_utf8mb4'heritageNewsletter',_utf8mb4'flagshipSplit',_utf8mb4'specSplit',_utf8mb4'calloutBand',_utf8mb4'compatibleProducts')))
) ENGINE=InnoDB AUTO_INCREMENT=38 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='Ordered typed sections for a category_pages row; UNIQUE(category_page_id, position) makes render order explicit (AC-2); its leftmost prefix also satisfies the FK-index requirement, so no separate KEY on category_page_id is added (avoids the redundant-index pattern flagged in db/INSIGHTS.md for product_specs).';
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `category_page_sections` WRITE;
/*!40000 ALTER TABLE `category_page_sections` DISABLE KEYS */;
INSERT INTO `category_page_sections` VALUES (1,1,1,'deviceGrid','flight-controllers',NULL,'Flight Controllers','STM32H743 autopilots running full Ardupilot — redundant IMUs, EW-ready return modes, CAN at the core.','{\"cards\": [{\"alt\": \"SkyModule X1 flight controller\", \"cta\": {\"to\": \"/drone-components/electronics/flight-controllers/skymodule-x1\", \"label\": \"View Product\"}, \"sku\": \"AAD-FC-7\", \"name\": \"SkyModule X1\", \"blurb\": \"Full-featured autopilot with triple-redundant IMUs, dual-camera switching and dual release-relay outputs, and RF-silent ballistic return.\", \"image\": \"/img/categories/drone-components/flight-controllers-1.jpg\", \"eyebrow\": \"Flight Controller\", \"features\": [\"STM32H743\", \"3× IMU\", \"Analog + Digital FPV\"], \"keyAdvantage\": \"Keeps flying when comms and GPS are gone — triple redundancy and a silent, compass-guided return for EW-contested airspace.\"}, {\"alt\": \"SkyModule X1-Lite flight controller\", \"cta\": {\"to\": \"/drone-components/electronics/flight-controllers/skymodule-x1-lite\", \"label\": \"View Product\"}, \"sku\": \"AAD-FC-7L\", \"name\": \"SkyModule X1-Lite\", \"blurb\": \"Compact autopilot for weight-sensitive platforms — dual IMU, native digital FPV, no adapter modules required.\", \"image\": \"/img/categories/drone-components/flight-controllers-2.jpg\", \"eyebrow\": \"Flight Controller\", \"features\": [\"STM32H743\", \"2× IMU\", \"Digital FPV\"], \"keyAdvantage\": \"FC7-class resilience at lower weight — native digital FPV means no adapter modules to add bulk or failure points.\"}], \"columns\": 2}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(2,1,2,'deviceGrid','edge-compute',NULL,'Edge Compute','Onboard compute that brings perception and autonomy to the airframe.','{\"cards\": [{\"alt\": \"ComputeNode Z edge compute module\", \"cta\": {\"to\": \"/drone-components/electronics/edge-compute/computenode-z\", \"label\": \"View Product\"}, \"sku\": \"AAD-ComputeNode-AI\", \"name\": \"ComputeNode Z\", \"blurb\": \"Modular onboard compute platform for tactical UAS, built on a CM4/CM5 base. Takes camera input over Ethernet or MIPI, links to the flight controller via CAN and UART, and powers directly from the airframe bus (9–34V) — the perception and autonomy host on the AAD stack. AI inference scales with the mission: add a Hailo accelerator to reach up to 26 TOPS of onboard compute.\", \"image\": \"/img/categories/drone-components/edge-compute.jpg\", \"eyebrow\": \"Edge Compute Module\", \"features\": [\"CAN + UART → FC\", \"Ethernet · MIPI Camera In\", \"9–34V\", \"CM4 / CM5\", \"Up to 26 TOPS · Hailo\"], \"keyAdvantage\": \"Scalable inference on the aircraft itself — fully air-gapped, with no cloud or datalink dependency, and expandable to up to 26 TOPS with a Hailo accelerator.\"}], \"columns\": 1}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(3,1,3,'deviceGrid','gnss-navigation',NULL,'GNSS & Navigation','Dual-band positioning engineered to keep working when the spectrum is contested.','{\"cards\": [{\"alt\": \"GeoNav Dual GNSS receiver\", \"cta\": {\"to\": \"/drone-components/electronics/gnss-navigation/geonav-dual\", \"label\": \"View Product\"}, \"sku\": \"AAD-GeoNav-DB\", \"name\": \"GeoNav Dual\", \"blurb\": \"Dual-band L1+L5 receiver tracking six constellations and up to 135 satellites. Simultaneous dual-band reception detects spoofing, and a hardware relay lets the flight controller physically cut GPS power on detection. GPS III–ready.\", \"image\": \"/img/categories/drone-components/gnss.jpg\", \"eyebrow\": \"GNSS Receiver\", \"features\": [\"L1 + L5\", \"Anti-Spoofing Relay\", \"6 Constellations\", \"135 Satellites\"], \"keyAdvantage\": \"Anti-spoofing at the hardware level — on detection, the relay physically cuts GPS power, so false coordinates can\'t leak into the flight stack. Not just a software warning.\"}], \"columns\": 1}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(4,1,4,'deviceGrid','sensors',NULL,'Sensors','External, CAN-connected sensing — heading, airspeed, and a configurable hub — mounted away from interference.','{\"cards\": [{\"alt\": \"FieldSense magnetometer\", \"cta\": {\"to\": \"/drone-components/electronics/sensors/fieldsense\", \"label\": \"View Product\"}, \"sku\": \"AAD-FieldSense\", \"name\": \"FieldSense\", \"blurb\": \"High-precision RM3100 compass over I2C, mounted clear of motor interference for a clean heading reference.\", \"image\": \"/img/categories/drone-components/sensors-1.jpg\", \"eyebrow\": \"Magnetometer\", \"features\": [\"RM3100\", \"I2C\", \"EMI-Immune\"], \"keyAdvantage\": \"RM3100 noise floor is ~75× lower than a typical MEMS magnetometer — a trustworthy heading even on high-current multirotors.\"}, {\"alt\": \"FieldSense CAN magnetometer\", \"cta\": {\"to\": \"/drone-components/electronics/sensors/fieldsense-can\", \"label\": \"View Product\"}, \"sku\": \"AAD-FieldSense-CAN\", \"name\": \"FieldSense CAN\", \"blurb\": \"RM3100 compass on the CAN bus with a 7–34V input — daisy-chains onto the same backbone as the rest of the stack.\", \"image\": \"/img/categories/drone-components/sensors-2.jpg\", \"eyebrow\": \"Magnetometer\", \"features\": [\"RM3100\", \"CAN\", \"7–34V\"], \"keyAdvantage\": \"Same RM3100 precision, now on CAN — one fewer dedicated port and a clean daisy-chain into the existing bus.\"}, {\"alt\": \"AirFlow CAN airspeed sensor\", \"cta\": {\"to\": \"/drone-components/electronics/sensors/airflow-can\", \"label\": \"View Product\"}, \"sku\": \"AAD-AirFlow-CAN\", \"name\": \"AirFlow CAN\", \"blurb\": \"CAN airspeed sensor reading up to 550 km/h — accurate true-airspeed data for fixed-wing and VTOL platforms.\", \"image\": \"/img/categories/drone-components/sensors-3.jpg\", \"eyebrow\": \"Airspeed\", \"features\": [\"Airspeed\", \"550 km/h\", \"CAN\"], \"keyAdvantage\": \"True airspeed up to 550 km/h on the CAN bus — reliable stall-margin and cruise data for high-speed fixed-wing and VTOL.\"}, {\"alt\": \"MultiSense CAN sensor hub\", \"cta\": {\"to\": \"/drone-components/electronics/sensors/multisense\", \"label\": \"View Product\"}, \"sku\": \"AAD-MultiSense\", \"name\": \"MultiSense\", \"blurb\": \"One CAN sensor hub, six factory configurations — combine GNSS, compass, airspeed, and barometer in a single module.\", \"image\": \"/img/categories/drone-components/sensors-4.jpg\", \"eyebrow\": \"Sensor Hub\", \"features\": [\"6 Configs\", \"CAN\", \"GNSS + Compass + Baro\"], \"keyAdvantage\": \"Six sensors\' worth of capability in a single SKU — fewer parts to source, wire, and certify, and faster integration.\"}], \"columns\": 2, \"ctaVariant\": \"link\"}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(5,1,5,'deviceGrid','power-servo',NULL,'Power & Servo','Distribution, monitoring, and servo control from 14S to 16S — all on the CAN bus.','{\"cards\": [{\"alt\": \"CAN PMU 16S power module\", \"cta\": {\"to\": \"/drone-components/electronics/power-servo/can-pmu-16s\", \"label\": \"View Product\"}, \"sku\": \"AAD-PMU-16S\", \"name\": \"CAN PMU 16S\", \"blurb\": \"High-current power monitoring unit — 200A continuous on 16S LiPo, with telemetry over CAN.\", \"image\": \"/img/categories/drone-components/power-servo-1.jpg\", \"eyebrow\": \"Power Module\", \"features\": [\"200A cont.\", \"16S\", \"CAN\"], \"keyAdvantage\": \"200A continuous on 16S with CAN telemetry — headroom for heavy-lift platforms with no derating.\"}, {\"alt\": \"CAN PMU Lite 14S power module\", \"cta\": {\"to\": \"/drone-components/electronics/power-servo/can-pmu-lite-14s\", \"label\": \"View Product\"}, \"sku\": \"AAD-PMU-L14S\", \"name\": \"CAN PMU Lite 14S\", \"blurb\": \"Lighter power monitoring unit for mid-size platforms — 100A continuous on 14S, CAN telemetry.\", \"image\": \"/img/categories/drone-components/power-servo-2.jpg\", \"eyebrow\": \"Power Module\", \"features\": [\"100A cont.\", \"14S\", \"CAN\"], \"keyAdvantage\": \"Full CAN power monitoring at a fraction of the weight — right-sized for mid-class platforms that don\'t need 200A.\"}, {\"alt\": \"PowerCore EX power expansion board\", \"cta\": {\"to\": \"/drone-components/electronics/power-servo/powercore-ex\", \"label\": \"View Product\"}, \"sku\": \"AAD-POWERCORE-EX\", \"name\": \"PowerCore EX\", \"blurb\": \"Expansion board for SkyModule X1 — adds BEC output, 120A peak current sensing, and 6× servo rails.\", \"image\": \"/img/categories/drone-components/power-servo-3.jpg\", \"eyebrow\": \"Power Expansion\", \"features\": [\"BEC 4A · 5–8V\", \"120A peak\", \"6× Servo\"], \"keyAdvantage\": \"Bolts power, sensing, and six servo rails onto FC7 — full capability without a separate board stack.\"}, {\"alt\": \"PowerRail 14S servo distribution rail\", \"cta\": {\"to\": \"/drone-components/electronics/power-servo/powerrail-14s\", \"label\": \"View Product\"}, \"sku\": \"AAD-POWERRAIL-14S\", \"name\": \"PowerRail 14S\", \"blurb\": \"Servo distribution rail with a high-current BEC — 14S/65V input feeding up to 12 servos at 10A.\", \"image\": \"/img/categories/drone-components/power-servo-4.jpg\", \"eyebrow\": \"Servo Rail\", \"features\": [\"BEC 10A · 5–12V\", \"14S / 65V\", \"12× Servo\"], \"keyAdvantage\": \"Drives up to 12 servos at 10A straight off 14S — no separate high-current servo BEC required.\"}, {\"alt\": \"ServoNode x4 CAN servo node\", \"cta\": {\"to\": \"/drone-components/electronics/power-servo/servonode-x4\", \"label\": \"View Product\"}, \"sku\": \"AAD-SERVONODE-X4\", \"name\": \"ServoNode x4\", \"blurb\": \"CAN-connected servo node — four PWM/DSHOT channels with an onboard BEC, isolating servo loads from the FC.\", \"image\": \"/img/categories/drone-components/power-servo-5.jpg\", \"eyebrow\": \"Servo Control\", \"features\": [\"4× PWM/DSHOT\", \"CAN\", \"BEC 4A · 5–8V\"], \"keyAdvantage\": \"Isolates servo loads from the flight controller over CAN — a servo short or stall never reaches the autopilot.\"}], \"columns\": 2, \"ctaVariant\": \"link\"}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(6,2,1,'explainer',NULL,NULL,'One Imaging System. Any Interface.','No two platforms integrate the same way. AAD cameras ship in the connector your airframe needs — same imaging quality, the interface that fits.','{\"banner\": {\"alt\": \"AAD camera interface options — analog, digital, and MIPI connectors\", \"image\": \"/img/categories/cameras/interface-kbcta.jpg\"}, \"minicards\": [{\"label\": \"Analog\", \"description\": \"Direct video output for legacy FPV links and analog transmission chains where simplicity and low latency win.\"}, {\"label\": \"Digital\", \"description\": \"Networked digital video (Ethernet / RTSP) for high-resolution streaming and multi-consumer architectures.\"}, {\"label\": \"MIPI\", \"description\": \"MIPI CSI-2 for the lowest-latency, board-level connection straight into the onboard compute module.\"}]}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(7,2,2,'valueGrid',NULL,NULL,'Glass That Holds Up Edge to Edge','Detection only works if the image is clean everywhere — not just in the center of the frame. AAD cameras use high-quality lenses engineered for minimal distortion and consistent image quality across the entire field of view.','{\"cards\": [{\"icon\": \"/img/categories/cameras/glass-1.svg\", \"title\": \"Minimal Distortion\", \"description\": \"Low-distortion optics keep straight lines straight and geometry true across the full field of view — essential for accurate detection and targeting.\"}, {\"icon\": \"/img/categories/cameras/glass-2.svg\", \"title\": \"Edge-to-Edge Sharpness\", \"description\": \"Consistent resolution from center to corner. A target at the edge of the frame stays as clear and detectable as one in the middle.\"}, {\"icon\": \"/img/categories/cameras/glass-3.svg\", \"title\": \"Sensor-Matched Optics\", \"description\": \"Every lens is matched to its sensor to extract maximum usable resolution and light — sensor and optics engineered together as one system.\"}]}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(8,2,3,'comparison',NULL,NULL,'Daylight or Thermal — Built for Both','Choose the sensor that matches the mission profile. Both feed the same onboard AI pipeline.','{\"columns\": [{\"label\": \"Daylight · Visible Spectrum\", \"title\": \"Optix\", \"bullets\": [\"Maximum detail and color information\", \"High-resolution daylight target detection\", \"Streams directly to ComputeNode Z\"], \"description\": \"High-resolution visible imaging for clear-condition detection, identification, and situational awareness.\"}, {\"label\": \"Thermal · All Conditions\", \"title\": \"ThermIX\", \"bullets\": [\"Detection at night and in low visibility\", \"Sees through smoke and obscurants\", \"Pairs with thermal-trained AI models\"], \"description\": \"Thermal imaging that sees through darkness, smoke, and adverse weather — when the visible spectrum can\'t.\"}]}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(9,2,4,'productRows',NULL,NULL,'AAD Camera Systems',NULL,'{\"rows\": [{\"alt\": \"AAD Optix daylight camera\", \"cta\": {\"to\": \"/drone-components/cameras/Optix-d\", \"label\": \"View Product\"}, \"sku\": \"AAD-CAM-Optix\", \"body\": \"High-resolution visible-spectrum camera available with a Gigabit Ethernet or MIPI CSI-2 interface. Streams H.264 / MJPEG over RTSP for real-time daylight target detection, feeding ComputeNode Z directly.\", \"name\": \"Optix\", \"badge\": \"Daylight\", \"image\": \"/img/categories/cameras/Optix.jpg\", \"category\": \"Daylight Camera\", \"features\": [\"Type: Visible spectrum (daylight)\", \"Interface: Gigabit Ethernet or MIPI CSI-2\", \"Streaming: H.264 / MJPEG (RTSP)\", \"Resolution: 1920 × 1080 (2 MP)\", \"FOV: Configurable — any FOV on request\"]}, {\"alt\": \"AAD ThermIX thermal camera\", \"cta\": {\"to\": \"/drone-components/cameras/ThermIX\", \"label\": \"View Product\"}, \"sku\": null, \"body\": \"Uncooled thermal imaging camera for all-conditions operation — detection at night, through smoke, and in adverse weather. Pairs with thermal-trained AI models and feeds ComputeNode Z directly.\", \"name\": \"ThermIX\", \"badge\": \"Thermal\", \"image\": \"/img/categories/cameras/ThermIX.jpg\", \"category\": \"Thermal Camera\", \"features\": [\"SKU: pending\", \"Type: Uncooled thermal (LWIR)\", \"Interface options: Analog · Digital\", \"Resolution: 640 × 480\", \"Frame rate: 50 FPS\", \"FOV: Configurable — any FOV on request\"]}]}','2026-07-21 13:02:55','2026-07-21 13:02:56'),(10,2,5,'diagramBand',NULL,NULL,'Camera, Compute & AI — Built to Work as One','AAD builds the camera, the ComputeNode Z compute, and the Vanta-AI models together. Every frame streams straight into on-board detection — no adapters, no cloud — and because the models are tuned to our own cameras, accuracy is higher straight out of the box. One integrated pipeline, maximum performance.\n\nCameras can ship with a representative training dataset matched to your targets and conditions — available on request, so your models start closer to mission-ready.','{\"note\": \"Cameras can ship with a representative training dataset matched to your targets and conditions — available on request, so your models start closer to mission-ready.\", \"steps\": [{\"icon\": \"/img/categories/cameras/flow-1.svg\", \"label\": \"Camera\", \"detail\": \"Optix / ThermIX\"}, {\"icon\": \"/img/categories/cameras/flow-2.svg\", \"label\": \"ComputeNode Z\", \"detail\": \"Onboard Compute\"}, {\"icon\": \"/img/categories/cameras/flow-3.svg\", \"label\": \"Vanta-AI\", \"detail\": \"Detect & ID\"}, {\"icon\": \"/img/categories/cameras/flow-4.svg\", \"label\": \"Maximum Performance\"}], \"details\": [{\"text\": \"Optix daylight and ThermIX thermal cameras, with sensor and optics engineered together and output in the interface your platform uses. Clean, low-latency frames built to be read by a machine — not just a pilot.\", \"title\": \"Camera\"}, {\"text\": \"The onboard compute module that ingests every frame and runs inference at the edge — no ground link, no cloud. Scalable headroom to run AAD\'s detection models in real time.\", \"title\": \"ComputeNode Z\"}, {\"text\": \"AAD\'s detection and identification models, trained in-house and tuned to the exact camera profile — so the system doesn\'t just see motion, it classifies the target, day or night.\", \"title\": \"Vanta-AI\"}, {\"text\": \"Because one team builds all three, there are no integration gaps between sensor, compute, and model — delivering higher detection accuracy and lower latency than any mix-and-match stack.\", \"title\": \"Maximum Performance\"}], \"variant\": \"dark\"}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(11,3,1,'productRows',NULL,NULL,'Thermal Sensor Technologies','Compact, multi-mission thermal optics on a 12-micron 640×480 core — usable as clip-on, stand-alone sight, handheld monocular, or helmet-mounted goggle.','{\"rows\": [{\"alt\": \"AAD TTM-18 thermal sight\", \"cta\": {\"to\": \"/products/ttm-18\", \"label\": \"View Product\"}, \"sku\": null, \"body\": \"A compact, multi-mission thermal sight — clip-on ahead of a day optic, stand-alone riflescope, handheld viewer, or helmet-mounted. 12-micron 640×480 core, flip-to-side QD mount that holds zero, and an integrated IR laser pointer. Optional 1,000-yard LRF.\", \"name\": \"TTM-18\", \"badge\": \"Thermal Sight\", \"image\": \"/img/categories/thermal-optics/ttm-18.jpg\", \"category\": \"Clip-On / Stand-Alone Thermal Sight\", \"features\": [\"640 × 480 · 12 µm\", \"Clip-On\", \"IR Laser\", \"Optional LRF 1000 yd\"]}, {\"alt\": \"AAD TTM-14 thermal monocular / goggle\", \"cta\": {\"to\": \"/products/ttm-14\", \"label\": \"View Product\"}, \"sku\": null, \"body\": \"A rugged thermal monocular in the standard PVS-14 form factor — handheld or helmet-mounted for hands-free use. The same 12-micron 640×480 core, IR laser pointer, and IP67 build, cutting through fog, foliage and haze. Optional 1,000-yard LRF.\", \"name\": \"TTM-14\", \"badge\": \"Thermal Monocular\", \"image\": \"/img/categories/thermal-optics/ttm-14.jpg\", \"category\": \"Thermal Monocular / Goggle\", \"features\": [\"640 × 480 · 12 µm\", \"PVS-14 Form Factor\", \"Helmet-Mount\", \"Optional LRF 1000 yd\"]}], \"columns\": 2}','2026-07-21 13:02:55','2026-07-21 13:02:56'),(12,3,2,'valueGrid',NULL,NULL,'Why Thermal','Thermal sees what light-based sensors can\'t — heat — so it works where night vision and the naked eye fail.','{\"cards\": [{\"icon\": \"/img/categories/thermal-optics/why-total-darkness.svg\", \"title\": \"Total Darkness\", \"description\": \"Detects targets by their heat signature with no ambient light at all — passive, day or night.\"}, {\"icon\": \"/img/categories/thermal-optics/why-cuts-through-obscurants.svg\", \"title\": \"Cuts Through Obscurants\", \"description\": \"Sees through smoke, dust, fog and haze that blind visible and image-intensified optics.\"}, {\"icon\": \"/img/categories/thermal-optics/why-reveals-concealed-targets.svg\", \"title\": \"Reveals Concealed Targets\", \"description\": \"Heat gives away targets hidden by foliage, camouflage and concealment — a decisive ISR edge.\"}], \"variant\": \"dark\", \"redBorder\": true}','2026-07-21 13:02:55','2026-07-21 13:33:19'),(13,4,1,'deviceGrid',NULL,NULL,'Advanced Day/Night Digital','On-device computing, Ultra HD imaging, integrated ranging, and ballistic-data exchange in one ruggedized device — observe, measure, record, and engage from a single optic, day or night.','{\"cards\": [{\"alt\": \"AAD DNBN-5 day/night binocular\", \"cta\": {\"to\": \"/products/dnbn-5\", \"label\": \"View Product\"}, \"sku\": null, \"name\": \"DNBN-5\", \"blurb\": \"Latest-generation binocular on an Ultra HD 4K+ sensor — about 33% sharper than the prior generation — with 4K recording, 240 FPS slow-motion, a built-in IR illuminator, and BIX ballistic-data exchange.\", \"image\": \"/img/categories/night-vision/dnbn-5.jpg\", \"features\": [\"5th-Gen Day/Night Binocular\", \"Ultra HD 4K+\", \"240 FPS\", \"IR Illuminator\", \"BIX\"]}, {\"alt\": \"AAD DNBN-4 day/night binocular\", \"cta\": {\"to\": \"/products/dnbn-4\", \"label\": \"View Product\"}, \"sku\": null, \"name\": \"DNBN-4\", \"blurb\": \"4K Ultra HD day/night binocular with a built-in laser rangefinder to 1,000 yards, BIX ballistic exchange, a battle-management and tactical-navigation app over Bluetooth, and a weather-resistant build.\", \"image\": \"/img/categories/night-vision/dnbn-4.jpg\", \"features\": [\"4K Day/Night Binocular + LRF\", \"4K Ultra HD\", \"LRF · 1000 yd\", \"BIX\", \"Tactical Nav\"]}, {\"alt\": \"AAD DNWS-5 day/night weapon sight\", \"cta\": {\"to\": \"/products/dnws-5\", \"label\": \"View Product\"}, \"sku\": null, \"name\": \"DNWS-5\", \"blurb\": \"Ultra HD day/night weapon sight with dual-stream video and internal recording, an integrated ballistic calculator, recoil-activated slow-motion capture, a smart mil-dot reticle with editor, and optional laser rangefinder.\", \"image\": \"/img/categories/night-vision/dnws-5.jpg\", \"features\": [\"Day/Night Weapon Sight\", \"Ultra HD\", \"Ballistic Calc\", \"Smart Reticle\", \"Optional LRF\"]}], \"columns\": 3}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(14,4,2,'deviceGrid',NULL,NULL,'Night Vision — Image Intensification','The foundational low-light capability for dismounted operators, vehicle crews, and aviators. Mil-spec photocathode and tube-grade options, autogated power supplies, manual gain, and modern dovetail and bayonet mounts.','{\"cards\": [{\"alt\": \"AAD PVS-14 night vision monocular\", \"cta\": {\"to\": \"/products/pvs-14\", \"label\": \"View Product\"}, \"sku\": null, \"name\": \"PVS-14\", \"blurb\": \"The benchmark single-tube monocular — passive, lightweight night observation for handheld, head-, helmet-mounted or weapon-side use.\", \"image\": \"/img/categories/night-vision/pvs-14.jpg\", \"features\": [\"Single-Tube I² Monocular\", \"Single-Tube I²\", \"Multi-Mount\", \"Passive\"]}, {\"alt\": \"AAD PS31 BNVD-40 dual-tube night vision goggle\", \"cta\": {\"to\": \"/products/ps31-bnvd-40\", \"label\": \"View Product\"}, \"sku\": null, \"name\": \"PS31 BNVD-40\", \"blurb\": \"Dual-tube binocular goggle in the BNVD-40 configuration — true depth perception and a wide field of view for dismounted operators and aviators.\", \"image\": \"/img/categories/night-vision/ps31-bnvd-40.jpg\", \"features\": [\"Dual-Tube Goggle\", \"Dual-Tube\", \"Depth Perception\", \"Autogated\"]}, {\"alt\": \"AAD PS31 BNVD-51 dual-tube night vision goggle\", \"cta\": {\"to\": \"/products/ps31-bnvd-51\", \"label\": \"View Product\"}, \"sku\": null, \"name\": \"PS31 BNVD-51\", \"blurb\": \"The same dual-tube depth-perception performance in the BNVD-51 configuration, with the 51-series interpupillary and mount profile.\", \"image\": \"/img/categories/night-vision/ps31-bnvd-51.jpg\", \"features\": [\"Dual-Tube Goggle\", \"Dual-Tube\", \"BNVD-51\", \"Autogated\"]}, {\"alt\": \"AAD NVM14 modular night vision monocular\", \"cta\": {\"to\": \"/products/nvm14\", \"label\": \"View Product\"}, \"sku\": null, \"name\": \"NVM14\", \"blurb\": \"A modular monocular for handheld, head- or helmet-mounted and weapon-side use, with standard dovetail and bayonet interfaces.\", \"image\": \"/img/categories/night-vision/nvm14.jpg\", \"features\": [\"Modular I² Monocular\", \"Modular\", \"Multi-Mount\", \"I²\"]}], \"columns\": 2}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(15,4,3,'diagramBand',NULL,NULL,'BIX — Ballistic Information Exchange','BIX lets compatible AAD digital optics share ranging and ballistic data directly between devices — no bolt-on accessories, no third-party apps. A spotter ranges a target and the shooter\'s optic has the firing solution, enabling integrated solutions for designated marksmen, reconnaissance teams, and small-unit precision fires.','{\"steps\": [{\"label\": \"Spotter Ranges\"}, {\"label\": \"BIX Data Exchange\"}, {\"label\": \"Shooter Solution\"}], \"visuals\": [{\"alt\": \"BIX ballistic information exchange overview diagram\", \"image\": \"/img/categories/night-vision/bix-diagram-main.svg\", \"isSvg\": true}, {\"alt\": \"BIX ballistic information exchange diagram, part 2\", \"image\": \"/img/categories/night-vision/bix-diagram-2.svg\", \"isSvg\": true}, {\"alt\": \"BIX ballistic information exchange diagram, part 3\", \"image\": \"/img/categories/night-vision/bix-diagram-3.svg\", \"isSvg\": true}]}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(16,5,1,'trustBar',NULL,NULL,NULL,NULL,'{\"items\": [{\"icon\": \"/img/drone-components/trust-usa.svg\", \"label\": \"Made in USA\"}, {\"icon\": \"/img/drone-components/trust-ndaa.png\", \"label\": \"NDAA Compliant\"}], \"background\": {\"image\": \"/img/drone-components/trust-1.png\"}}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(17,5,2,'categoryBlocks',NULL,NULL,'Two Building Blocks. One Stack.','The heart of every AAD platform — imaging plus avionics and compute, all engineered to operate as a single system.','{\"blocks\": [{\"cta\": {\"to\": \"/drone-components/electronics\", \"label\": \"Explore Electronics\"}, \"image\": \"/img/drone-components/blocks-1.png\", \"title\": \"Electronics\", \"bullets\": [\"Flight Controllers — SkyModule X1 / FC7-Lite\", \"GNSS & Navigation — GeoNav Dual\", \"Sensors — FieldSense · AirFlow · MultiSense\", \"Power & Servo — PMU · PowerRail · ServoNode\", \"Edge Compute — ComputeNode Z\"], \"description\": \"The avionics core — flight control, navigation, sensing, power, and edge compute, all on one CAN backbone.\"}, {\"cta\": {\"to\": \"/cameras\", \"label\": \"Explore Cameras\"}, \"image\": \"/img/drone-components/blocks-2.png\", \"title\": \"Cameras\", \"bullets\": [\"Optix daylight & ThermIX thermal\", \"Analog · digital · MIPI interfaces\", \"Sensor and optics engineered together\", \"Feeds ComputeNode Z / Vanta-AI\"], \"description\": \"Daylight and thermal imaging engineered to feed the onboard AI directly — delivered in the interface your platform needs.\"}]}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(18,5,3,'problemSolution',NULL,NULL,NULL,NULL,'{\"problem\": {\"intro\": \"Drone manufacturers often source flight controllers, navigation systems, sensors, and cameras from multiple vendors.\", \"title\": \"Most Drone Programs Fail at Integration\", \"results\": [\"Compatibility issues\", \"Long integration cycles\", \"Vendor lock-in\", \"Increased certification complexity\", \"Reduced system reliability\"]}, \"solution\": {\"text\": \"Cameras and electronics share a common architecture, a single CAN communication standard, and one development philosophy — so integration stops being the hard part.\", \"title\": \"Every Component Engineered to Work Together From Day One\"}}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(19,5,4,'valueGrid',NULL,NULL,'Designed for Integration at Scale',NULL,'{\"cards\": [{\"title\": \"Faster Integration\", \"description\": \"Single ecosystem architecture reduces engineering effort and compatibility risk.\"}, {\"title\": \"Simplified Procurement\", \"description\": \"One supplier for cameras, avionics, and compute.\"}, {\"title\": \"Reduced Program Risk\", \"description\": \"Controlled hardware stack and domestic manufacturing improve supply chain resilience.\"}, {\"title\": \"Future-Ready Architecture\", \"description\": \"Built for autonomous, AI-enabled drone programs.\"}], \"numbered\": true}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(20,5,5,'heritageNewsletter',NULL,NULL,NULL,NULL,'{\"cta\": {\"to\": \"/about-us\", \"label\": \"About AAD\"}, \"text\": \"AAD is the aerospace and defense division of AeroDefences Corp, a Silicon Valley technology company recognized for advancing digital thermal optics and imaging systems for more than three decades. Today, that expertise powers a new generation of American-made drone technologies engineered for government, defense, and industrial operators.\", \"title\": \"Backed by 30 Years of Innovation\", \"images\": [\"/img/drone-components/heritage-1.png\", \"/img/drone-components/heritage-2.png\"], \"newsletter\": {\"text\": \"Receive product announcements, technical briefings, and industry insights from AAD engineers.\", \"title\": \"Stay Ahead of Emerging UAS Technologies\", \"buttonLabel\": \"Receive\"}}','2026-07-21 13:02:55','2026-07-21 13:02:55'),(21,6,1,'flagshipSplit','vanta-ai',NULL,NULL,NULL,'{\"cta\": {\"to\": \"/ai-solutions#vanta-ai\", \"label\": \"Explore Vanta-AI\"}, \"body\": \"Vanta-AI brings onboard detection and identification to the aircraft — processing daylight and thermal imagery in real time, fully air-gapped. But a model is only as good as the data behind it. That\'s why AAD owns the whole pipeline: we generate real, representative datasets and train the models ourselves.\", \"visual\": {\"alt\": \"Vanta-AI detection and classification overlay\", \"image\": \"/img/ai-solutions/flagship-visual.png\"}, \"heading\": \"Vanta-AI\", \"tagline\": \"See More. Understand Faster.\", \"checklist\": [\"Real-time detection & classification\", \"Target identification by signature\", \"Daylight & thermal imagery\", \"Air-gapped, no cloud dependency\"]}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(22,6,2,'valueGrid',NULL,NULL,NULL,NULL,'{\"cards\": [{\"icon\": \"/img/ai-solutions/pillar-dataset.svg\", \"title\": \"Real Dataset Generation\", \"description\": \"Most AI vendors hand you a model and hope your data matches it. We do the opposite. AAD captures and builds representative datasets on the exact cameras the model will run on — matched to your targets, your backgrounds, and your operating conditions, in both daylight and thermal. The model is trained on what it will actually see in the field.\"}, {\"icon\": \"/img/ai-solutions/pillar-training.svg\", \"title\": \"In-House Model Training\", \"description\": \"Detection and identification models are trained, validated, and optimized entirely by AAD — then compiled for onboard inference and pre-loaded per customer order. No outsourced training, no black-box weights you can\'t account for. As your target set evolves, we retrain and redeploy to keep accuracy where it needs to be.\"}], \"redBorder\": true}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(23,6,3,'diagramBand',NULL,NULL,'From Dataset to Strike — One Pipeline','AAD owns every layer, so the model is trained on what it will actually see and runs where the decision has to be made — on the aircraft.','{\"steps\": [{\"icon\": \"/img/ai-solutions/pipeline-icon-1.svg\", \"label\": \"Real Datasets\", \"detail\": \"Captured on the same cameras, targets & conditions\"}, {\"icon\": \"/img/ai-solutions/pipeline-icon-2.svg\", \"label\": \"In-House Training\", \"detail\": \"Trained, validated & compiled by AAD\"}, {\"icon\": \"/img/ai-solutions/pipeline-icon-3.svg\", \"label\": \"Onboard Inference\", \"detail\": \"Runs air-gapped on ComputeNode Z\"}, {\"icon\": \"/img/ai-solutions/pipeline-icon-4.svg\", \"label\": \"Detection & ID\", \"detail\": \"Targets boxed & classified in real time\"}, {\"icon\": \"/img/ai-solutions/pipeline-icon-5.svg\", \"label\": \"Terminal Guidance\", \"detail\": \"AeroLock flies the final approach\"}], \"background\": {\"image\": \"/img/ai-solutions/pipeline-bg.png\"}}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(24,6,4,'valueGrid',NULL,NULL,'Where It\'s Deployed','One perception-and-autonomy stack, applied across the missions that matter most.','{\"cards\": [{\"icon\": \"/img/ai-solutions/usecase-1.png\", \"title\": \"Moving-Target Engagement\", \"description\": \"Hold the lock on targets that move and maneuver.\"}, {\"icon\": \"/img/ai-solutions/usecase-2.png\", \"title\": \"Strike & Interception\", \"description\": \"Vision-locked terminal approach onto a designated target, holding guidance through jamming and spoofing.\"}, {\"icon\": \"/img/ai-solutions/usecase-3.png\", \"title\": \"Counter-UAS\", \"description\": \"Detect and classify small aerial threats against open sky, then cue interception.\"}, {\"icon\": \"/img/ai-solutions/usecase-4.png\", \"title\": \"Search & Detection\", \"description\": \"Find heat signatures and objects of interest through smoke, foliage and degraded visibility.\"}], \"illustration\": true}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(25,6,5,'categoryBlocks',NULL,NULL,'Beyond Perception — Autonomous Flight','Two AAD-developed software capabilities that take the aircraft from \"sees the target\" to \"flies the mission.\"','{\"pills\": true, \"blocks\": [{\"cta\": {\"to\": \"/ai-solutions/aerolock\", \"label\": \"Learn More\"}, \"image\": \"/img/ai-solutions/aerolock.png\", \"title\": \"AeroLock\", \"anchor\": \"aerolock\", \"bullets\": [\"Up to 1 km\", \"Vision-Based\", \"EW / REB Resilient\", \"Spoof-Proof\", \"GPS-Independent\"], \"eyebrow\": \"AAD Software\", \"subtitle\": \"Autonomous Terminal Approach\", \"description\": \"AeroLock takes over for the final approach — autonomously guiding the aircraft onto a designated target at ranges up to 1 km. Because it follows the target visually rather than GPS coordinates, it holds guidance through electronic-warfare (EW/REB) jamming and GPS spoofing — exactly where coordinate-based navigation fails.\"}, {\"cta\": {\"to\": \"/ai-solutions#mission-autopilot\", \"label\": \"Learn More\"}, \"image\": \"/img/ai-solutions/mission-autopilot.png\", \"title\": \"Mission Autopilot\", \"anchor\": \"mission-autopilot\", \"bullets\": [\"Waypoint Navigation\", \"Route Planning\", \"Automatic Mission Flight\", \"Hands-Off\"], \"eyebrow\": \"AAD Software\", \"subtitle\": \"Waypoint & Route Automation\", \"description\": \"Plan it once, fly it hands-off. Mission Autopilot executes pre-set waypoints and routes for fully automatic mission flight — takeoff, navigation, and the mission profile run autonomously on the AAD flight stack, with no operator stick time required.\"}], \"ctaVariant\": \"link\"}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(26,6,6,'valueGrid',NULL,NULL,'When GPS Is Gone, Vision Isn\'t','AAD autonomy follows what the camera sees, not a coordinate it\'s told to trust — so it keeps working exactly where electronic warfare breaks coordinate-based navigation.','{\"dark\": true, \"cards\": [{\"icon\": \"/img/ai-solutions/contested-icon-1.svg\", \"title\": \"GPS-Denied Navigation\", \"description\": \"Vision-based guidance locks onto the target itself, so the mission continues with no satellite fix at all.\"}, {\"icon\": \"/img/ai-solutions/contested-icon-2.svg\", \"title\": \"EW / REB Resilient\", \"description\": \"Holds guidance through active jamming of GPS and command links — no ground-station signal required in the loop.\"}, {\"icon\": \"/img/ai-solutions/contested-icon-3.svg\", \"title\": \"Spoof-Proof\", \"description\": \"Because it doesn\'t trust an external position, a falsified GPS signal can\'t pull the aircraft off its target.\"}], \"background\": {\"image\": \"/img/ai-solutions/contested-bg.png\"}}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(27,6,7,'specSplit',NULL,NULL,NULL,NULL,'{\"cta\": {\"to\": \"/drone-components/electronics/edge-compute/computenode-z\", \"label\": \"View ComputeNode Z\"}, \"body\": \"Vanta-AI is compiled for onboard inference and runs on ComputeNode Z — a field-swappable compute module with a dedicated Hailo accelerator delivering up to 26 TOPS, with no link to a ground station. Detection, identification and terminal guidance all happen on the drone, with direct CAN access to SkyModule X1.\", \"visual\": {\"alt\": \"ComputeNode Z compute module\", \"image\": \"/img/ai-solutions/ComputeNode-visual.png\"}, \"heading\": \"On the Aircraft, Air-Gapped\", \"specCard\": {\"rows\": [{\"label\": \"Compute\", \"value\": \"Raspberry Pi CM4 / CM5\"}, {\"label\": \"AI accelerator\", \"value\": \"Hailo · up to 26 TOPS\"}, {\"label\": \"Connectivity\", \"value\": \"CSI · Ethernet · PCIe · HDMI\"}, {\"label\": \"Flight link\", \"value\": \"CAN to SkyModule X1\"}, {\"label\": \"Power\", \"value\": \"9–34 V (3S–8S)\"}, {\"label\": \"Operation\", \"value\": \"Air-gapped · onboard\"}], \"chips\": [\"Air-Gapped · No Cloud\", \"Up to 26 TOPS · Hailo\", \"CAN to SkyModule\", \"Field-Swappable\"], \"title\": \"ComputeNode Z — at a glance\"}}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(28,6,8,'heritageNewsletter',NULL,NULL,NULL,NULL,'{\"cta\": {\"to\": \"/drone-components/electronics/edge-compute/computenode-z\", \"label\": \"See the Hardware\"}, \"text\": \"AAD software runs on AAD hardware — perception on ComputeNode Z, flight on SkyModule — so detection, terminal guidance, and mission autonomy share one architecture instead of fighting across vendors.\", \"title\": \"One Stack, From Pixel to Flight\", \"images\": [\"/img/ai-solutions/heritage-bg.png\"]}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(29,7,1,'calloutBand',NULL,NULL,NULL,NULL,'{\"tag\": \"Key Advantage\", \"text\": \"Coordinate-based guidance fails the moment GPS is jammed or spoofed. AeroLock follows the target itself — visually — so the final approach holds exactly where other systems break.\"}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(30,7,2,'diagramBand',NULL,NULL,'Lock On and Commit','From designation to impact, the aircraft tracks the target visually — no operator stick time and no coordinate to spoof.','{\"steps\": [{\"icon\": \"/img/ai-solutions/aerolock/how-it-works-icon-1.svg\", \"label\": \"Designate Target\", \"detail\": \"Operator marks the target in the video feed\"}, {\"icon\": \"/img/ai-solutions/aerolock/how-it-works-icon-2.svg\", \"label\": \"Visual Lock\", \"detail\": \"AeroLock locks onto the target\'s appearance\"}, {\"icon\": \"/img/ai-solutions/aerolock/how-it-works-icon-3.svg\", \"label\": \"Autonomous Tracking\", \"detail\": \"Holds the target through maneuver and jamming\"}, {\"icon\": \"/img/ai-solutions/aerolock/how-it-works-icon-4.svg\", \"label\": \"Terminal Approach\", \"detail\": \"Guides the aircraft onto the target, up to 1 km\"}], \"background\": {\"image\": \"/img/ai-solutions/aerolock/how-it-works-bg.png\"}}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(31,7,3,'valueGrid',NULL,NULL,'What AeroLock Does','Autonomy for the final, most contested seconds of the mission.','{\"cards\": [{\"title\": \"Autonomous Terminal Approach\", \"description\": \"Takes over the final approach and guides the aircraft onto a designated target at ranges up to 1 km.\"}, {\"title\": \"Vision-Based Tracking\", \"description\": \"Follows the target by its appearance in the camera feed, not by a coordinate it\'s told to trust.\"}, {\"title\": \"Holds Through Maneuver\", \"description\": \"Keeps the lock as the target moves, turns or accelerates during the approach.\"}, {\"title\": \"EW / REB Resilient\", \"description\": \"No ground-station link in the loop, so active jamming of GPS and command links can\'t break guidance.\"}, {\"title\": \"Spoof-Proof\", \"description\": \"Because it doesn\'t rely on external position, a falsified GPS signal can\'t pull the aircraft off target.\"}, {\"title\": \"GPS-Independent\", \"description\": \"Operates with no satellite fix at all — designed for fully GPS-denied airspace.\"}], \"columns\": 3, \"redBorder\": true}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(32,7,4,'comparison',NULL,NULL,'Beats Jamming & Spoofing','Coordinate-guided weapons trust an external position — jam or spoof it and they drift off target. AeroLock trusts only what it sees.','{\"dark\": true, \"columns\": [{\"image\": {\"alt\": \"\", \"image\": \"/img/ai-solutions/aerolock/beats-jamming-gps.png\"}, \"label\": \"Coordinate-Guided (GPS)\", \"title\": \"Coordinate-Guided (GPS)\", \"verdict\": \"Spoofed → Miss\", \"description\": \"A falsified or jammed position pulls the aircraft off the target — the closer it gets, the worse the error.\"}, {\"image\": {\"alt\": \"\", \"image\": \"/img/ai-solutions/aerolock/beats-jamming-vision.png\"}, \"label\": \"AeroLock Vision-Lock\", \"title\": \"AeroLock Vision-Lock\", \"verdict\": \"Locked → Hit\", \"description\": \"With no external position in the loop, there\'s nothing to jam or spoof — the lock holds straight to impact.\"}]}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(33,7,5,'valueGrid',NULL,NULL,'More Hits, Fewer Aborts','Why a vision-locked terminal approach lands the mission where coordinate guidance can\'t.','{\"cards\": [{\"icon\": \"/img/ai-solutions/aerolock/mission-effectiveness-icon-1.svg\", \"title\": \"Holds Through Maneuver\", \"description\": \"Keeps the lock as the target turns, brakes or accelerates — no lost track at the decisive moment.\"}, {\"icon\": \"/img/ai-solutions/aerolock/mission-effectiveness-icon-2.svg\", \"title\": \"Corrects to the Last Second\", \"description\": \"Closed-loop visual guidance keeps adjusting aim all the way to impact, not just at release.\"}, {\"icon\": \"/img/ai-solutions/aerolock/mission-effectiveness-icon-3.svg\", \"title\": \"No Pilot Skill Needed\", \"description\": \"Autonomy flies the hard final approach — the operator only has to designate the target.\"}, {\"icon\": \"/img/ai-solutions/aerolock/mission-effectiveness-icon-4.svg\", \"title\": \"Fewer Aborts\", \"description\": \"No satellite fix to lose means missions aren\'t scrubbed by jamming or a dropped GPS lock.\"}]}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(34,7,6,'valueGrid',NULL,NULL,'Where It\'s Deployed','Autonomy for engagements where coordinate navigation can\'t be trusted.','{\"cards\": [{\"icon\": \"/img/ai-solutions/aerolock/use-case-1.png\", \"title\": \"Strike & Interception\", \"description\": \"Vision-locked terminal approach onto a designated target, holding guidance through jamming and spoofing.\"}, {\"icon\": \"/img/ai-solutions/aerolock/use-case-2.png\", \"title\": \"Counter-UAS\", \"description\": \"Detect and classify small aerial threats against open sky, then cue interception.\"}, {\"icon\": \"/img/ai-solutions/aerolock/use-case-3.png\", \"title\": \"Moving-Target Engagement\", \"description\": \"Hold the lock on targets that move and maneuver.\"}, {\"icon\": \"/img/ai-solutions/aerolock/use-case-4.png\", \"title\": \"Precision Approach\", \"description\": \"Repeatable, hands-off final approach in contested airspace.\"}], \"background\": {\"image\": \"/img/ai-solutions/aerolock/use-cases-bg.png\"}, \"illustration\": true}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(35,7,7,'diagramBand',NULL,NULL,'From Detection to Lock','AeroLock is the terminal link in the AAD autonomy chain — handed a target by Vanta-AI after Mission Autopilot flies the ingress.','{\"steps\": [{\"icon\": \"/img/ai-solutions/aerolock/detection-lock-mission-autopilot.png\", \"label\": \"Mission Autopilot\", \"detail\": \"Flies the planned ingress to the target area\"}, {\"icon\": \"/img/ai-solutions/aerolock/detection-lock-vanta-ai.png\", \"label\": \"Vanta-AI\", \"detail\": \"Detects and cues the target in the live feed\"}, {\"icon\": \"/img/ai-solutions/aerolock/detection-lock-aerolock.png\", \"label\": \"AeroLock\", \"detail\": \"Locks on and flies the terminal approach\"}], \"photoSteps\": true}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(36,7,8,'specSplit',NULL,NULL,NULL,NULL,'{\"cta\": {\"to\": \"/drone-components/electronics/flight-controllers/skymodule-x1\", \"label\": \"View SkyModule X1\"}, \"body\": \"AeroLock runs on the AAD flight stack — executing on SkyModule X1 and driving the airframe directly, with the target feed coming from Optix-D or ThermIX cameras via ComputeNode Z. Everything stays onboard and air-gapped.\", \"visual\": {\"alt\": \"SkyModule X1 flight controller\", \"image\": \"/img/ai-solutions/aerolock/runs-on-visual.png\"}, \"heading\": \"On the AAD Flight Stack\", \"specCard\": {\"rows\": [{\"label\": \"MCU\", \"value\": \"STM32H743 · 2 MB\"}, {\"label\": \"Firmware\", \"value\": \"Full ArduPilot\"}, {\"label\": \"Redundancy\", \"value\": \"3× IMU · 2× Baro\"}, {\"label\": \"Compute link\", \"value\": \"CAN to ComputeNode Z\"}, {\"label\": \"Input\", \"value\": \"4–8S (max 34 V)\"}, {\"label\": \"Operation\", \"value\": \"Air-gapped · onboard\"}], \"chips\": [\"Runs on SkyModule X1\", \"Vision from Optix / ThermIX\", \"Air-Gapped · Onboard\", \"Up to 1 km\"], \"title\": \"SkyModule X1 — at a glance\"}}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(37,7,9,'compatibleProducts',NULL,NULL,'One Stack, From Pixel to Flight',NULL,'{\"cards\": [{\"cta\": {\"to\": \"/drone-components/electronics/flight-controllers/skymodule-x1\", \"label\": \"View\"}, \"name\": \"SkyModule X1\", \"image\": \"/img/ai-solutions/aerolock/runs-on-visual.png\"}, {\"cta\": {\"to\": \"/ai-solutions\", \"label\": \"View\"}, \"name\": \"Vanta-AI\", \"image\": \"/img/ai-solutions/aerolock/detection-lock-vanta-ai.png\"}, {\"cta\": {\"to\": \"/drone-components/electronics/edge-compute/computenode-z\", \"label\": \"View\"}, \"name\": \"ComputeNode Z\", \"image\": \"/img/ai-solutions/aerolock/compatible-ComputeNode.png\", \"eyebrow\": \"Compute\"}, {\"cta\": {\"to\": \"/ai-solutions#mission-autopilot\", \"label\": \"View\"}, \"name\": \"Mission Autopilot\", \"image\": \"/img/ai-solutions/aerolock/detection-lock-mission-autopilot.png\", \"eyebrow\": \"Autonomy\"}]}','2026-07-21 13:02:56','2026-07-21 13:02:56');
