  `hero_eyebrow` varchar(255) DEFAULT NULL,
  `hero_title` varchar(255) NOT NULL,
  `hero_title_highlights` json DEFAULT NULL,
  `hero_tagline` varchar(255) DEFAULT NULL,
  `hero_chips` json DEFAULT NULL,
  `hero_lead` text NOT NULL,
  `hero_ctas` json DEFAULT NULL,
  `hero_visual` json NOT NULL,
  `quick_nav` json DEFAULT NULL,
  `meta_title` varchar(255) DEFAULT NULL,
  `meta_description` varchar(500) DEFAULT NULL,
  `og_title` varchar(255) DEFAULT NULL,
  `og_description` varchar(500) DEFAULT NULL,
  `og_image` varchar(500) DEFAULT NULL,
  `canonical` varchar(500) DEFAULT NULL,
  `is_indexable` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_category_pages_slug` (`slug`),
  CONSTRAINT `chk_category_pages_hero_layout` CHECK ((`hero_layout` in (_utf8mb4'standard',_utf8mb4'pageHero')))
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='Additive landing-page content (SPEC-08), slug-keyed, decoupled from the categories taxonomy tree; SEO fields live here (not urls), resolved decision #4.';
