INSERT INTO `category_pages` VALUES (1,'drone-components/electronics','Drone Components',3,'[{\"to\": \"/\", \"label\": \"Home\"}, {\"to\": \"/drone-components\", \"label\": \"Drone Components\"}, {\"to\": \"/drone-components/electronics\", \"label\": \"Electronics\"}]','standard',NULL,'The Avionics Core, on One Bus','[\"on One Bus\"]',NULL,NULL,'Flight control, compute, navigation, sensing, and power — every module an independent SKU, all sharing CAN-bus compatibility and Ardupilot connector standards. Engineered to drop in and work together.',NULL,'{\"alt\": \"AAD avionics stack — flight controller, compute, and sensor modules on a CAN backbone\", \"image\": \"/img/categories/drone-components/hero.jpg\"}','[{\"label\": \"Flight Controllers\", \"anchor\": \"flight-controllers\"}, {\"label\": \"Edge Compute\", \"anchor\": \"edge-compute\"}, {\"label\": \"GNSS & Navigation\", \"anchor\": \"gnss-navigation\"}, {\"label\": \"Sensors\", \"anchor\": \"sensors\"}, {\"label\": \"Power & Servo\", \"anchor\": \"power-servo\"}]','Drone Components — The Avionics Core, on One Bus','Flight control, compute, navigation, sensing, and power — every module an independent SKU, all sharing CAN-bus compatibility and Ardupilot connector standards. Engineered to drop in and work together.','Drone Components — The Avionics Core, on One Bus','Flight control, compute, navigation, sensing, and power — every module an independent SKU, all sharing CAN-bus compatibility and Ardupilot connector standards. Engineered to drop in and work together.','/img/categories/drone-components/hero.jpg','/drone-components/electronics',1,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(2,'cameras','Cameras',1,'[{\"to\": \"/\", \"label\": \"Home\"}, {\"to\": \"/cameras\", \"label\": \"Cameras\"}]','pageHero',NULL,'Vision Engineered for the Mission','[\"for the Mission\"]',NULL,NULL,'Daylight and thermal imaging built as complete sensor-and-optics systems — delivered in the interface your platform actually uses, and feeding AAD\'s onboard AI directly. No adapters. No added latency.',NULL,'{\"alt\": \"AAD Cameras — Optix and ThermIX camera lineup\", \"image\": \"/img/categories/cameras/hero.jpg\"}',NULL,'Vision Engineered for the Mission','Daylight and thermal imaging built as complete sensor-and-optics systems — delivered in the interface your platform actually uses, and feeding AAD\'s onboard AI directly. No adapters. No added latency.','Vision Engineered for the Mission','Daylight and thermal imaging built as complete sensor-and-optics systems — delivered in the interface your platform actually uses, and feeding AAD\'s onboard AI directly. No adapters. No added latency.','/img/categories/cameras/hero.jpg','/cameras',1,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(3,'thermal-optics','Thermal Imaging',2,'[{\"to\": \"/\", \"label\": \"Home\"}, {\"to\": \"/thermal-optics\", \"label\": \"Thermal Imaging\"}]','standard',NULL,'Thermal Imaging',NULL,'See Heat. See Through.','[\"12-Micron · 640×480\", \"<25 mK NETD\", \"IR Laser Pointer\", \"IP67 · MIL-STD-810\"]','Thermal imaging gives the operator a decisive advantage in darkness, smoke, dust, fog, and visually degraded conditions — increasingly the primary sensor for ISR, perimeter and border surveillance, search and rescue, force protection, and weapon sighting. Compact, ruggedized, defense-grade.',NULL,'{\"alt\": \"AAD thermal imaging device viewing a heat signature\", \"image\": \"/img/categories/thermal-optics/hero.jpg\"}',NULL,NULL,NULL,NULL,NULL,NULL,'/thermal-optics',1,'2026-07-21 13:02:55','2026-07-21 13:02:56'),(4,'night-vision','Night Vision',4,'[{\"to\": \"/\", \"label\": \"Home\"}, {\"to\": \"/night-vision\", \"label\": \"Night Vision\"}]','standard','Own the Dark.','Night Vision & Digital Day/Night',NULL,NULL,NULL,'Two complementary families of low-light capability: combat-proven image-intensification (I²) for passive, lightweight, all-night observation, and advanced digital day/night optics that add on-device ranging, recording, and ballistic-data exchange in one ruggedized package.',NULL,'{\"alt\": \"AAD night vision optic — I² view, night vision\", \"image\": \"/img/categories/night-vision/hero.jpg\"}',NULL,'Night Vision & Digital Day/Night | AAD','Image-intensification (I²) night vision and digital day/night optics with integrated ranging, recording, and BIX ballistic-data exchange, from AAD.','Night Vision & Digital Day/Night | AAD','Image-intensification (I²) night vision and digital day/night optics with integrated ranging, recording, and BIX ballistic-data exchange, from AAD.','/img/categories/night-vision/hero.jpg','/night-vision',1,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(5,'drone-components','Drone Components',0,'[{\"to\": \"/\", \"label\": \"Home\"}, {\"to\": \"/drone-components\", \"label\": \"Drone Components\"}]','pageHero',NULL,'The Core of the Drone Stack','[\"Drone Stack\"]',NULL,NULL,'Cameras and electronics engineered to one standard and one CAN backbone — so imaging and the avionics core work together from day one. All NDAA-compliant, all built in America.',NULL,'{\"alt\": \"AAD camera and avionics lineup — the core of the drone stack\", \"image\": \"/img/drone-components/hero-1.png\"}',NULL,'Drone Components — The Core of the Drone Stack','Cameras and electronics engineered to one standard and one CAN backbone — so imaging and the avionics core work together from day one. All NDAA-compliant, all built in America.','Drone Components — The Core of the Drone Stack','Cameras and electronics engineered to one standard and one CAN backbone — so imaging and the avionics core work together from day one. All NDAA-compliant, all built in America.','/img/drone-components/hero-1.png','/drone-components',1,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(6,'ai-solutions','AI Solutions',5,'[{\"to\": \"/\", \"label\": \"Home\"}, {\"to\": \"/ai-solutions\", \"label\": \"AI Solutions\"}]','standard',NULL,'Intelligence That Runs on the Aircraft','[\"on the Aircraft\"]',NULL,NULL,'AAD\'s software stack puts perception and autonomy on the drone itself — air-gapped, real-time, and built for GPS-denied, EW-contested environments. From dataset to detection to terminal guidance, every layer is developed in-house.',NULL,'{\"alt\": \"Vanta-AI onboard detection running on an AAD aircraft\", \"image\": \"/img/ai-solutions/hero.png\"}',NULL,'AI Solutions — Intelligence That Runs on the Aircraft','AAD\'s software stack puts perception and autonomy on the drone itself — air-gapped, real-time, and built for GPS-denied, EW-contested environments.','AI Solutions — Intelligence That Runs on the Aircraft','AAD\'s software stack puts perception and autonomy on the drone itself — air-gapped, real-time, and built for GPS-denied, EW-contested environments.','/img/ai-solutions/hero.png','/ai-solutions',1,'2026-07-21 13:02:56','2026-07-21 13:02:56'),(7,'ai-solutions/aerolock','AeroLock',6,'[{\"to\": \"/\", \"label\": \"Home\"}, {\"to\": \"/ai-solutions\", \"label\": \"AI Solutions\"}, {\"to\": \"/ai-solutions/aerolock\", \"label\": \"AeroLock\"}]','standard',NULL,'AeroLock',NULL,'Lock On. Stay Locked.','[\"Up to 1 km\", \"Vision-Based\", \"EW / REB Resilient\", \"Spoof-Proof\", \"GPS-Independent\"]','Autonomous terminal approach — AeroLock guides the aircraft onto a designated target at ranges up to 1 km. Because it follows the target visually rather than GPS coordinates, it holds guidance through electronic-warfare jamming and GPS spoofing, exactly where coordinate-based navigation fails.',NULL,'{\"alt\": \"AeroLock terminal approach visual\", \"image\": \"/img/ai-solutions/aerolock/hero.png\"}',NULL,'AeroLock — Autonomous Terminal Approach','AeroLock guides the aircraft onto a designated target at ranges up to 1 km, holding guidance through GPS jamming and spoofing where coordinate-based navigation fails.','AeroLock — Autonomous Terminal Approach','AeroLock guides the aircraft onto a designated target at ranges up to 1 km, holding guidance through GPS jamming and spoofing where coordinate-based navigation fails.','/img/ai-solutions/aerolock/hero.png','/ai-solutions/aerolock',1,'2026-07-21 13:02:56','2026-07-21 13:02:56');
