INSERT INTO `product_faqs` VALUES (1,3,'How much onboard AI compute does ComputeNode Z provide?','Up to 26 TOPS of onboard inference via a Hailo accelerator, running on a field-swappable Raspberry Pi CM4/CM5 module — no cloud or datalink dependency.',1,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(2,3,'What is ComputeNode Z compatible with?','ComputeNode Z is built to run as one system on the AAD stack — it pairs with SkyModule X1, GeoNav Dual, Cameras and AI Solutions.',2,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(3,3,'How does ComputeNode Z connect?','It connects via FC link; Cameras; Networking.',3,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(4,3,'What\'s included in the box?','1× Drone Pi motherboard. Exact Hailo module, OS image and software stack, cooling and first-setup guide — see the Knowledge Base.',4,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(5,3,'Is ComputeNode Z NDAA-compliant and made in the USA?','Yes — ComputeNode Z is NDAA-compliant and made in the USA.',5,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(6,1,'What MCU and sensors does SkyModule X1 use?','An STM32H743 with 2 MB flash running full ArduPilot, backed by triple IMUs (ICM45686 ×2, BMI270) and dual DPS368 barometers for redundancy.',1,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(7,1,'What is SkyModule X1 compatible with?','SkyModule X1 is built to run as one system on the AAD stack — it pairs with GeoNav Dual, FieldSense CAN, PowerCore EX and PowerRail 14S.',2,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(8,1,'How does SkyModule X1 connect?','It connects via USB · SD card; 1× UART with RTS/CTS (SERIAL1); 6× UART · 2× CAN.',3,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(9,1,'What\'s included in the box?','1× H7-Basic V3 · 1× USB & Buzzer board · 4× damper grommets · JST-GH 1.25 mm cable set (3/4/5/6/7/8-pin).',4,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(10,1,'Is SkyModule X1 NDAA-compliant and made in the USA?','Yes — SkyModule X1 is NDAA-compliant and made in the USA.',5,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(11,2,'How is SkyModule X1-Lite different from the FC7?','It\'s a weight-optimized STM32H743 board with dual ICM42688-P IMUs, native digital FPV output and built-in gimbal and 4-in-1 ESC ports — FC7-class flight control without the adapter modules.',1,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(12,2,'What is SkyModule X1-Lite compatible with?','SkyModule X1-Lite is built to run as one system on the AAD stack — it pairs with SkyModule X1, GeoNav Dual, FieldSense CAN and ComputeNode Z.',2,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(13,2,'How does SkyModule X1-Lite connect?','It connects via GIMBAL; ESC 4-in-1; CAN.',3,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(14,2,'What\'s included in the box?','1× H7-Lite board · JST GH-1.25 mm cable set · ArduPilot firmware 4.5.5 and 4.6.3 with H7-Lite Defines · 3D models for the board and USB adapter.',4,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(15,2,'Is SkyModule X1-Lite NDAA-compliant and made in the USA?','Yes — SkyModule X1-Lite is NDAA-compliant and made in the USA.',5,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(16,4,'How does GeoNav Dual resist GPS spoofing?','Simultaneous L1+L5 reception detects spoofing, and a hardware relay physically cuts GPS power on detection — so false coordinates never reach the flight stack, not just a software warning.',1,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(17,4,'What is GeoNav Dual compatible with?','GeoNav Dual is built to run as one system on the AAD stack — it pairs with SkyModule X1, FieldSense CAN, MultiSense and AirFlow CAN.',2,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(18,4,'How does GeoNav Dual connect?','It connects via UART · UBX protocol @ 230400 bps (TX/RX); Compass over I2C (SDA/SCL); 5V · GND.',3,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(19,4,'What\'s included in the box?','1× GNSS module · 1× passive ceramic antenna (50×50×10 mm) · GNSS & I2C compass cables.',4,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(20,4,'Is GeoNav Dual NDAA-compliant and made in the USA?','Yes — GeoNav Dual is NDAA-compliant and made in the USA.',5,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(21,5,'Why does FieldSense use an RM3100 instead of a MEMS compass?','FieldSense uses an industrial RM3100 (PNI Sensor, USA) over I²C with 13 nT resolution and isolated coils for high noise immunity — a clear heading even on high-current multirotors.',1,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(22,5,'What is FieldSense compatible with?','FieldSense is built to run as one system on the AAD stack — it pairs with SkyModule X1, FieldSense CAN, GeoNav Dual and MultiSense.',2,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(23,5,'How does FieldSense connect?','It connects via I²C; Mount X forward, Y right (or in 90° multiples); Change address for multiple compasses.',3,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(24,5,'What\'s included in the box?','1× FieldSense (I²C) module with RM3100 sensor.',4,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(25,5,'Is FieldSense NDAA-compliant and made in the USA?','Yes — FieldSense is NDAA-compliant and made in the USA.',5,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(26,6,'How is FieldSense CAN different from the I²C FieldSense?','Same RM3100 precision, but as a DroneCAN node on the shared CAN bus (7–34 V, 2S–8S straight from the battery) with two connectors for daisy-chaining — one fewer dedicated port on the flight controller.',1,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(27,6,'What is FieldSense CAN compatible with?','FieldSense CAN is built to run as one system on the AAD stack — it pairs with SkyModule X1, GeoNav Dual, MultiSense and FieldSense.',2,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(28,6,'How does FieldSense CAN connect?','It connects via CAN · DroneCAN node on the shared CAN bus; Two CAN connectors for daisy-chaining; Pinout: CAN_H · CAN_L · VBAT · 5V · GND.',3,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(29,6,'What\'s included in the box?','1× FieldSense CAN module · CAN daisy-chain cabling.',4,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(30,6,'Is FieldSense CAN NDAA-compliant and made in the USA?','Yes — FieldSense CAN is NDAA-compliant and made in the USA.',5,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(31,7,'What airspeed range does AirFlow CAN measure?','Up to 550 km/h using MS5525 / DLVR-L10 / DLVR-L60 pressure sensors, over a DroneCAN interface immune to UAV power-system noise, with an included heating module for the pitot tube.',1,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(32,7,'What is AirFlow CAN compatible with?','AirFlow CAN is built to run as one system on the AAD stack — it pairs with SkyModule X1, GeoNav Dual, MultiSense and PowerRail 14S.',2,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(33,7,'How does AirFlow CAN connect?','It connects via 2× CAN connectors (CAN_H, CAN_L, VBAT, 5V, GND); Daisy-chain onto the shared CAN bus; Redundant dual-power feed.',3,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(34,7,'What\'s included in the box?','1× AirFlow CAN module · 1× pitot tube · 1× heating module · CAN cabling.',4,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(35,7,'Is AirFlow CAN NDAA-compliant and made in the USA?','Yes — AirFlow CAN is NDAA-compliant and made in the USA.',5,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(36,8,'What sensors are combined in MultiSense?','A single CAN module combining dual-band (L1+L5) GNSS, an industrial RM3100 magnetometer, airspeed up to 550 km/h and a BMP390 barometer — four sensors\' worth of capability in one node.',1,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(37,8,'What is MultiSense compatible with?','MultiSense is built to run as one system on the AAD stack — it pairs with SkyModule X1, GeoNav Dual, FieldSense CAN and AirFlow CAN.',2,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(38,8,'How does MultiSense connect?','It connects via CAN (DroneCAN) — joins the shared bus; Dual CAN connectors; VBAT 4–8S · 5V · GND.',3,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(39,8,'What\'s included in the box?','1× MultiSense module (selected configuration) · CAN cable set.',4,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(40,8,'Is MultiSense NDAA-compliant and made in the USA?','Yes — MultiSense is NDAA-compliant and made in the USA.',5,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(41,9,'What current and battery range does CAN PMU 16S handle?','8–16S input with 200 A continuous (400 A peak), delivering current measurement, ESC control and regulated power to the flight controller and peripherals over the CAN bus — short-circuit protected.',1,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(42,9,'What is CAN PMU 16S compatible with?','CAN PMU 16S is built to run as one system on the AAD stack — it pairs with SkyModule X1, PowerCore EX, PowerRail 14S and ServoNode x4.',2,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(43,9,'How does CAN PMU 16S connect?','It connects via Battery input — 8AWG terminals; 2× CAN outputs (regulated 24V) to FC & peripherals; 2× VBAT on Microfit.',3,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(44,9,'What\'s included in the box?','1× CAN PMU 16S 200A module. See the Knowledge Base for the full package contents diagram.',4,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(45,9,'Is CAN PMU 16S NDAA-compliant and made in the USA?','Yes — CAN PMU 16S is NDAA-compliant and made in the USA.',5,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(46,10,'How does CAN PMU Lite 14S compare to the 16S?','It\'s the lighter mid-class version: 8–14S input with 100 A continuous (160 A for 5 s, 320 A measurement limit), with the same CAN-bus power, monitoring and ESC control.',1,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(47,10,'What is CAN PMU Lite 14S compatible with?','CAN PMU Lite 14S is built to run as one system on the AAD stack — it pairs with SkyModule X1, PowerCore EX, PowerRail 14S and ServoNode x4.',2,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(48,10,'How does CAN PMU Lite 14S connect?','It connects via Battery input — Microfit; 2× CAN outputs (regulated 24V) to FC and peripherals; 2× VBAT on Microfit.',3,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(49,10,'What\'s included in the box?','CAN PMU Lite 14S module with connection cabling — see the Knowledge Base for the full package list.',4,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(50,10,'Is CAN PMU Lite 14S NDAA-compliant and made in the USA?','Yes — CAN PMU Lite 14S is NDAA-compliant and made in the USA.',5,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(51,11,'What does PowerCore EX add to a SkyModule X1?','It stacks directly on the FC7 (matching 30.5×30.5 mm) via a 22-pin FFC ribbon, adding 60–70 A continuous (120 A peak) current sensing, a 4 A 5V/8V BEC and six servo channels — no separate board stack.',1,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(52,11,'What is PowerCore EX compatible with?','PowerCore EX is built to run as one system on the AAD stack — it pairs with SkyModule X1, PowerRail 14S, ServoNode x4 and CAN PMU 16S.',2,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(53,11,'How does PowerCore EX connect?','It connects via To FC7 — 22-pin FFC 0.5 mm ribbon (stacks on top); XT60 — battery / ESC power; 6× servo headers (GND, VS, PWM), 5V/8V selectable.',3,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(54,11,'What\'s included in the box?','1× PowerCore EX board · XT60 connector · pre-installed servo header strip · 22-pin FFC 0.5 mm ribbon to FC.',4,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(55,11,'Is PowerCore EX NDAA-compliant and made in the USA?','Yes — PowerCore EX is NDAA-compliant and made in the USA.',5,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(56,12,'How many servos can PowerRail 14S drive?','Up to 12 PWM channels with a high-current 5V/7.4V/8V BEC (10 A continuous, 20 A peak) straight from 4–14S (max 65 V) — and outputs 1–4 can read ESC telemetry with a SkyModule X1.',1,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(57,12,'What is PowerRail 14S compatible with?','PowerRail 14S is built to run as one system on the AAD stack — it pairs with SkyModule X1, PowerCore EX, ServoNode x4 and CAN PMU 16S.',2,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(58,12,'How does PowerRail 14S connect?','It connects via Power input — up to 14S (65V) via Microfit; 12× servo outputs (GND, VS, PWM); channels 1–4 can read ESC telemetry (with SkyModule X1); PWM input — up to 12 signals from the FC via JST-GH 1.25 14-pin.',3,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(59,12,'What\'s included in the box?','1× PowerRail 14S · 1× JST-GH 1.25 mm 14-pin cable · mounting standoffs.',4,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(60,12,'Is PowerRail 14S NDAA-compliant and made in the USA?','Yes — PowerRail 14S is NDAA-compliant and made in the USA.',5,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(61,13,'How does ServoNode x4 protect the flight controller?','It powers and controls four servos plus an ESC over DroneCAN and isolates the load from the controller — so a servo short or stall (up to 34 V / 8S, selectable 5V/8V output) never reaches the autopilot.',1,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(62,13,'What is ServoNode x4 compatible with?','ServoNode x4 is built to run as one system on the AAD stack — it pairs with SkyModule X1, PowerRail 14S, PowerCore EX and CAN PMU 16S.',2,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(63,13,'How does ServoNode x4 connect?','It connects via CAN — DroneCAN (dual connectors) to the flight controller; 4× servo outputs (GND, VS, PWM); ESC output with telemetry (GND, TELEM, PWM); PWM or DSHOT.',3,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(64,13,'What\'s included in the box?','1× ServoNode x4 node. Full box contents are detailed in the Knowledge Base.',4,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(65,13,'Is ServoNode x4 NDAA-compliant and made in the USA?','Yes — ServoNode x4 is NDAA-compliant and made in the USA.',5,'2026-07-21 13:02:55','2026-07-21 13:02:55');
/*!40000 ALTER TABLE `product_faqs` ENABLE KEYS */;
UNLOCK TABLES;
DROP TABLE IF EXISTS `product_features`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `product_features` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `product_id` bigint unsigned NOT NULL,
  `position` int unsigned NOT NULL,
  `icon` varchar(500) DEFAULT NULL,
  `title` varchar(255) NOT NULL,
  `body` text NOT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_product_features_product_id` (`product_id`),
  CONSTRAINT `fk_product_features_product` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=61 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `product_features` WRITE;
/*!40000 ALTER TABLE `product_features` DISABLE KEYS */;
INSERT INTO `product_features` VALUES (1,3,1,'/img/products/computenode-z/hl-1.svg','Field-Swappable Module','Carries a Raspberry Pi CM4 or CM5 as a field-replaceable module — upgrade compute without touching the airframe.'),(2,3,2,'/img/products/computenode-z/hl-2.svg','Up To 26 TOPS','A dedicated Hailo accelerator delivers up to 26 TOPS of onboard inference, with no link to a ground station.'),(3,3,3,'/img/products/computenode-z/hl-3.svg','Camera I/O','CSI inputs (2× on CM4, 1× on CM5) feed raw data straight to the ISP, plus 100 Mbit Ethernet for digital cameras.'),(4,3,4,'/img/products/computenode-z/hl-4.svg','PCIe & HDMI Output','PCIe expansion and ESD-protected Mini HDMI for displays, recorders and downlink hardware.'),(5,1,1,'/img/products/skymodule-x1/hl-1.svg','Triple-IMU Redundancy','Three IMUs and dual barometers — a single sensor failure never compromises flight stability.'),(6,1,2,'/img/products/skymodule-x1/hl-2.svg','Compass Return Without GPS','Returns home by compass at a set pitch — without yawing the copter — when satellites are jammed or lost.'),(7,1,3,'/img/products/skymodule-x1/hl-3.svg','Ballistic Aiming Assistant','An OSD aiming reticle offset by pitch/roll within the camera FOV, on both analog and digital FPV.'),(8,1,4,'/img/products/skymodule-x1/hl-4.svg','Anti-EW Video Switching','Switches the VTX channel synchronously from a transmitter switch to dodge electronic-warfare video jamming.'),(9,2,1,'/img/products/skymodule-x1-lite/hl-1.svg','Compact Dual-IMU Autopilot','STM32H743 with two ICM42688-P IMUs delivers FC7-class flight control in a weight-optimized form factor.'),(10,2,2,'/img/products/skymodule-x1-lite/hl-2.svg','Dedicated Gimbal Port','A native gimbal port isolates payload control from flight-critical paths — no external adapter module required.'),(11,2,3,'/img/products/skymodule-x1-lite/hl-3.svg','Integrated 4-in-1 ESC','Built-in 4-in-1 ESC interface with current, telemetry and voltage sense over a single connector.'),(12,2,4,'/img/products/skymodule-x1-lite/hl-4.svg','Native Digital FPV','Native digital FPV video output drives modern video systems directly, with no adapter modules.'),(13,5,1,'/img/products/fieldsense/hl-1.svg','RM3100 Isolated Coils','The industrial RM3100 sensor from PNI Sensor (USA) uses isolated coils for stable, repeatable magnetic readings.'),(14,5,2,'/img/products/fieldsense/hl-2.svg','13 nT Resolution','A fine 13 nT resolution delivers a precise, low-noise heading reference for accurate navigation.'),(15,5,3,'/img/products/fieldsense/hl-3.svg','EMI Immunity','High noise immunity holds a clear heading even on high-current multirotors where motors defeat other magnetometers.'),(16,5,4,'/img/products/fieldsense/hl-4.svg','Light 2 g Module','At just 2 g and 35 × 24 mm, FieldSense adds negligible weight and footprint to any airframe.'),(17,6,1,'/img/products/fieldsense-can/hl-1.svg','RM3100 Precision','Industrial PNI RM3100 sensor (USA) with 13 nT resolution and isolated coils for a stable, high-resolution heading.'),(18,6,2,'/img/products/fieldsense-can/hl-2.svg','Single-Cable Daisy-Chain','CAN / DroneCAN node joins the shared AAD backbone — daisy-chain it on with one cable through its dual CAN connectors.'),(19,6,3,'/img/products/fieldsense-can/hl-3.svg','EMI Immunity','Isolated coils plus a digital CAN bus shrug off motor and ESC noise that swamps other magnetometers on high-current builds.'),(20,6,4,'/img/products/fieldsense-can/hl-4.svg','FC7 Compass Return','The recommended magnetometer for the SkyModule X1 “compass return without GPS” feature in EW-contested airspace.'),(21,4,1,'/img/products/geonav-dual/hl-1.svg','Dual-Band L1 + L5','Simultaneous reception on L1 (1575.42 MHz) and L5 (1176.45 MHz) for faster fix, multipath rejection and stronger anti-spoofing.'),(22,4,2,'/img/products/geonav-dual/hl-2.svg','Hardware Anti-Spoof Relay','On spoofing detection a hardware relay physically cuts GPS power — false coordinates never enter the flight stack, not just a software warning.'),(23,4,3,'/img/products/geonav-dual/hl-3.svg','6 Constellations · 135 Sats','GPS, BeiDou, GLONASS, Galileo, QZSS and NAVIC — tracking up to 135 satellites simultaneously for a robust, redundant fix.'),(24,4,4,'/img/products/geonav-dual/hl-4.svg','Built-In Compass','Integrated QMC5883L magnetometer over I2C with orientation referenced at the mounting hole for clean heading data.'),(25,9,1,'/img/products/can-pmu-16s/hl-1.svg','200A Continuous on 16S','VBAT OUT delivers up to 200 A continuous (400 A peak) on 8–16S, with 8AWG terminals for the battery input.'),(26,9,2,'/img/products/can-pmu-16s/hl-2.svg','DroneCAN Telemetry','Voltage and current measurement streamed over UAVCAN / DroneCAN — EM-noise immunity through the CAN bus.'),(27,9,3,'/img/products/can-pmu-16s/hl-3.svg','ESC Control + Power','Dedicated PWM output with ESC telemetry pins (GND, TELEM, PWM, OFF) and VBAT power for the ESC, DSHOT or PWM.'),(28,9,4,'/img/products/can-pmu-16s/hl-4.svg','Remote ESC OFF','Sends an OFF signal to shut down a DC-DC ESC for safe ground handling (confirm support with the ESC maker).'),(29,10,1,'/img/products/can-pmu-lite-14s/hl-1.svg','100A Continuous on 14S','VBAT for the ESC up to 100 A continuous, with a 160 A (5 s) burst and a 320 A measurement limit.'),(30,10,2,'/img/products/can-pmu-lite-14s/hl-2.svg','CAN Telemetry','UAVCAN / DroneCAN voltage and current telemetry with EM-noise immunity over the CAN bus.'),(31,10,3,'/img/products/can-pmu-lite-14s/hl-3.svg','ESC Control & Power','A separate PWM output with ESC telemetry (GND, TELEM, PWM, OFF), selectable DSHOT or PWM, plus VBAT power.'),(32,10,4,'/img/products/can-pmu-lite-14s/hl-4.svg','Remote ESC OFF','Sends an OFF signal to disable a DC-DC ESC (confirm support with the ESC maker).'),(33,11,1,'/img/products/powercore-ex/hl-1.svg','Direct FC7 Stack','Matching 30.5 × 30.5 mm footprint mounts on top of SkyModule X1 to minimize cable runs.'),(34,11,2,'/img/products/powercore-ex/hl-2.svg','120A Peak Current Sensing','60–70 A continuous, 120 A peak — accurate energy data to the autopilot for state-of-charge tracking.'),(35,11,3,'/img/products/powercore-ex/hl-3.svg','6× Servo 5V/8V BEC','Six-channel servo rail with selectable 5V or 8V output for standard and HV servos, no external adapters.'),(36,11,4,'/img/products/powercore-ex/hl-4.svg','ESD-Protected PWM','Hardened servo outputs — anything over 5V is shunted to GND to protect downstream electronics.'),(37,12,1,'/img/products/powerrail-14s/hl-1.svg','High-Current BEC','10A continuous and 20A peak straight from the battery — enough headroom for heavy servo loads.'),(38,12,2,'/img/products/powerrail-14s/hl-2.svg','Selectable Voltage','Output rail switchable between 5V, 7.4V and 8V to match your servos and actuators.'),(39,12,3,'/img/products/powerrail-14s/hl-3.svg','Up to 12 PWM','Carries up to 12 PWM signals from the controller via a single JST-GH 1.25 14-pin link.'),(40,12,4,'/img/products/powerrail-14s/hl-4.svg','ESC Telemetry on Ch 1–4','Outputs 1–4 can switch from supplying power to receiving ESC telemetry when paired with H7-Basic.'),(41,8,1,'/img/products/multisense/hl-1.svg','Six Configs, One SKU','A single AAD-MultiSense part number ships in six factory configurations of GNSS, compass, airspeed and barometer.'),(42,8,2,'/img/products/multisense/hl-2.svg','Dual-Band GNSS','L1+L5 dual-band reception for faster, more robust positioning — L1 at 4.5 dBi, L5 at 2.1 dBi antenna gain.'),(43,8,3,'/img/products/multisense/hl-3.svg','Industrial RM3100 Compass','High-stability RM3100 magnetometer for reliable heading, including compass-guided return without GPS.'),(44,8,4,'/img/products/multisense/hl-4.svg','Airspeed to 550 km/h','Optional airspeed sensing (MS5525 or DLVR-L10) measures up to 550 km/h for fixed-wing and high-speed platforms.'),(45,13,1,'/img/products/servonode-x4/hl-1.svg','4× PWM / DSHOT over CAN','Four independent servo outputs (GND, VS, PWM) driven over UAVCAN / DroneCAN — no signal wires back to the autopilot.'),(46,13,2,'/img/products/servonode-x4/hl-2.svg','ESC Output + Telemetry','A separate ESC control output (GND, TELEM, PWM) supporting PWM or DSHOT, with motor telemetry returned over the bus.'),(47,13,3,'/img/products/servonode-x4/hl-3.svg','Load Isolated From the FC','Servo and ESC loads sit on the node, not the controller — a servo fault never reaches the flight controller.'),(48,13,4,'/img/products/servonode-x4/hl-4.svg','EM-Noise Immunity','Moving control onto the differential CAN bus keeps actuator switching noise off the autopilot\'s sensitive lines.'),(49,7,1,'/img/products/airflow-can/hl-1.svg','Airspeed to 550 km/h','Measures dynamic pressure across the full UAV envelope — accurate readings from loiter speed up to 550 km/h.'),(50,7,2,'/img/products/airflow-can/hl-2.svg','MS5525 / DLVR Options','Two sensor variants — MS5525 or DLVR-L10/L60 — to match the airframe\'s speed range and pressure resolution.'),(51,7,3,'/img/products/airflow-can/hl-3.svg','DroneCAN Digital Link','Pure digital CAN telemetry to the autopilot — no analog ADC line to pick up motor and power-system noise.'),(52,7,4,'/img/products/airflow-can/hl-4.svg','Heated Pitot','Integrated heating module clears icing and condensation, keeping the pitot accurate in cold, humid air.'),(53,14,1,'/img/products/Optix-d/hl-1.svg','STARVIS 2 + Clear HDR','Back-illuminated 2.4 MP sensor with Clear HDR — clean image through dawn, dusk, fog and high-contrast urban scenes.'),(54,14,2,'/img/products/Optix-d/hl-2.svg','Ultra-Low Latency','Under 50 ms glass-to-stream over Ethernet — and under 10 ms on the MIPI CSI-2 variant, so the pilot and the autopilot act on what they see in real time.'),(55,14,3,'/img/products/Optix-d/hl-3.svg','AI-Ready Pipeline','Native digital output built to be read directly by an onboard detection model — no frame grabber in the loop.'),(56,14,4,'/img/products/Optix-d/hl-4.svg','Native Digital Ethernet','UDP / RTSP H.264 / H.265 over a single Ethernet link — no analog VTX and no transcoding step.'),(57,15,1,'/img/products/ThermIX/hl-1.svg','High-Sensitivity VOx Core','A 12 µm uncooled FPA at NETD < 15 mK delivers clean thermal contrast in the hardest conditions.'),(58,15,2,'/img/products/ThermIX/hl-2.svg','Sees Through the Dark','Detection in total darkness, smoke, fog and degraded visibility — day or night, no illumination required.'),(59,15,3,'/img/products/ThermIX/hl-3.svg','Two Output Variants','Digital Ethernet (ThermIX-D) for onboard AI, or analog CVBS plus USB UVC (ThermIX-A) for legacy FPV chains.'),(60,15,4,'/img/products/ThermIX/hl-4.svg','Interchangeable Optics','9 mm wide or 25 mm long-range Germanium lenses, matched to the mission profile.');
/*!40000 ALTER TABLE `product_features` ENABLE KEYS */;
UNLOCK TABLES;
DROP TABLE IF EXISTS `product_images`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `product_images` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `product_id` bigint unsigned NOT NULL,
  `url` varchar(500) NOT NULL,
  `alt` varchar(255) DEFAULT NULL,
  `is_primary` tinyint(1) NOT NULL DEFAULT '0',
  `sort_order` int unsigned NOT NULL DEFAULT '0',
  `primary_product_id` bigint unsigned GENERATED ALWAYS AS ((case when (`is_primary` = 1) then `product_id` end)) VIRTUAL COMMENT 'Virtual column used only to enforce at most one is_primary=1 row per product_id via a UNIQUE index; NULL (non-primary rows) do not collide under UNIQUE.',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_product_images_primary_product` (`primary_product_id`),
  KEY `idx_product_images_product_id` (`product_id`),
  CONSTRAINT `fk_product_images_product` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=16 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `product_images` WRITE;
/*!40000 ALTER TABLE `product_images` DISABLE KEYS */;
INSERT INTO `product_images` (`id`, `product_id`, `url`, `alt`, `is_primary`, `sort_order`) VALUES (1,3,'/img/products/computenode-z/computenode-z.png','ComputeNode Z',1,1),(2,1,'/img/products/skymodule-x1/skymodule-x1.png','SkyModule X1',1,1),(3,2,'/img/products/skymodule-x1-lite/skymodule-x1-lite.png','SkyModule X1-Lite',1,1),(4,5,'/img/products/fieldsense/fieldsense.png','FieldSense',1,1),(5,6,'/img/products/fieldsense-can/fieldsense-can.png','FieldSense CAN',1,1),(6,4,'/img/products/geonav-dual/geonav-dual.png','GeoNav Dual',1,1),(7,9,'/img/products/can-pmu-16s/can-pmu-16s.png','CAN PMU 16S',1,1),(8,10,'/img/products/can-pmu-lite-14s/can-pmu-lite-14s.png','CAN PMU Lite 14S',1,1),(9,11,'/img/products/powercore-ex/powercore-ex.png','PowerCore EX',1,1),(10,12,'/img/products/powerrail-14s/powerrail-14s.png','PowerRail 14S',1,1),(11,8,'/img/products/multisense/multisense.png','MultiSense',1,1),(12,13,'/img/products/servonode-x4/servonode-x4.png','ServoNode x4',1,1),(13,7,'/img/products/airflow-can/airflow-can.png','AirFlow CAN',1,1),(14,14,'/img/products/Optix-d/Optix-d.png','Optix-D',1,1),(15,15,'/img/products/ThermIX/ThermIX.png','ThermIX',1,1);
/*!40000 ALTER TABLE `product_images` ENABLE KEYS */;
UNLOCK TABLES;
DROP TABLE IF EXISTS `product_relations`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `product_relations` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `product_id` bigint unsigned NOT NULL,
  `related_product_id` bigint unsigned DEFAULT NULL,
  `related_category_id` bigint unsigned DEFAULT NULL,
  `relation_type` enum('compatible','accessory','related','replacement') NOT NULL,
  `group_label` varchar(255) DEFAULT NULL,
  `label` varchar(255) DEFAULT NULL,
  `link` varchar(500) DEFAULT NULL,
  `image` varchar(500) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_product_relations_product_id` (`product_id`),
  KEY `idx_product_relations_related_product_id` (`related_product_id`),
  KEY `idx_product_relations_related_category_id` (`related_category_id`),
  CONSTRAINT `fk_product_relations_product` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `fk_product_relations_related_category` FOREIGN KEY (`related_category_id`) REFERENCES `categories` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `fk_product_relations_related_product` FOREIGN KEY (`related_product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `ck_product_relations_no_self` CHECK (((`related_product_id` is null) or (`related_product_id` <> `product_id`))),
  CONSTRAINT `ck_product_relations_target` CHECK ((((`related_product_id` is not null) and (`related_category_id` is null) and (`label` is null) and (`link` is null)) or ((`related_category_id` is not null) and (`related_product_id` is null) and (`label` is null) and (`link` is null)) or ((`related_product_id` is null) and (`related_category_id` is null) and (`label` is not null) and (`link` is not null))))
) ENGINE=InnoDB AUTO_INCREMENT=61 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='Polymorphic product relations; exactly one of related_product_id/related_category_id must be set (ck_product_relations_xor_target), and a product cannot relate to itself (ck_product_relations_no_self).';
/*!40101 SET character_set_client = @saved_cs_client */;

