DROP TABLE IF EXISTS `product_sections`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `product_sections` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `product_id` bigint unsigned NOT NULL,
  `position` int unsigned NOT NULL,
  `type` varchar(32) NOT NULL,
  `data` json NOT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_product_sections_product_position` (`product_id`,`position`),
  CONSTRAINT `fk_product_sections_product` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `chk_product_sections_type` CHECK ((`type` in (_utf8mb4'edgeToEdgeOptics',_utf8mb4'wieldAiIntegration',_utf8mb4'thermalOptics')))
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='Ordered typed per-product sections (SPEC-11), mirroring category_page_sections; UNIQUE(product_id, position) makes per-product render order explicit and satisfies the FK-index requirement (no separate KEY on product_id).';
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `product_sections` WRITE;
/*!40000 ALTER TABLE `product_sections` DISABLE KEYS */;
INSERT INTO `product_sections` VALUES (1,14,1,'edgeToEdgeOptics','{\"images\": [{\"alt\": \"Optix-D edge-to-edge sharpness test image\", \"url\": \"/img/products/Optix-d/edge-center.png\", \"note\": \"Every signature locked — corners and center.\", \"caption\": \"AAD Optix-D · Edge-to-Edge\", \"variant\": \"center\"}, {\"alt\": \"Typical lens center-only sharpness sample\", \"url\": \"/img/products/Optix-d/edge-typical.png\", \"note\": \"Edges soften — targets missed at the corners.\", \"caption\": \"Typical Lens · Center Only\", \"variant\": \"typical\"}], \"heading\": \"Edge-to-Edge Optics\", \"oneLine\": \"A target the AI can\'t resolve is a target it can\'t engage — so we don\'t cut corners on the glass.\", \"paragraphs\": [\"Most low-cost camera lenses are only sharp in the center of the frame. Toward the edges the image softens, and detection and identification models start to miss or misclassify targets that drift away from the middle of the picture.\", \"Optix-D uses a high-quality lens that holds a uniform, sharp image across the entire frame. Targets are detected and identified just as reliably at the edges as they are dead-center — which matters most in the seconds before a target leaves the field of view.\"]}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(2,14,2,'wieldAiIntegration','{\"cta\": {\"link\": \"/ai-solutions\", \"label\": \"Explore Vanta-AI →\"}, \"lead\": \"Optix-D isn\'t a camera that happens to feed an AI — it\'s built for ours. Vanta-AI runs detection and identification on the live video, drawing a box and a confidence score around every target the model recognises.\", \"image\": {\"alt\": \"Live Vanta-AI detection overlay on the Optix-D video feed\", \"url\": \"/img/products/Optix-d/vanta-ai.png\", \"caption\": \"Live Vanta-AI detections on the Optix-D feed — class label and confidence per target.\"}, \"heading\": \"Tuned for Our Models\", \"features\": [{\"body\": \"We can provide a representative sample dataset — and a fully trained model — so you can validate detection and identification before you commit.\", \"title\": \"Test Dataset on Request\"}, {\"body\": \"We set the tonemapping and image tuning ourselves, calibrated to the conditions our models are trained on — not a generic factory profile.\", \"title\": \"In-House Tonemapping & Tuning\"}, {\"body\": \"Because we build both, sensor output and model expectations line up — stronger detection and fewer missed targets out of the box.\", \"title\": \"Camera & Model, Matched\"}]}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(3,15,1,'thermalOptics','{\"lead\": \"Two field-swappable Germanium lenses on the same 640×480 core. Field of view is the trade-off — a wider lens keeps more of the scene in frame, a longer lens magnifies distant heat signatures so the model detects and identifies them sooner.\", \"lenses\": [{\"name\": \"9 mm Lens\", \"blurb\": \"The all-round default — broad situational awareness for mid-range strike, FPV and ISR, keeping the target in frame through aggressive terminal maneuvers.\", \"specs\": [{\"label\": \"Focal\", \"value\": \"9 mm\"}, {\"label\": \"Aperture\", \"value\": \"F/1.2\"}, {\"label\": \"FOV\", \"value\": \"46° × 35°\"}, {\"label\": \"Focus\", \"value\": \"Fixed ∞\"}, {\"label\": \"Material\", \"value\": \"Germanium\"}], \"subtitle\": \"Wide · 46° × 35°\"}, {\"name\": \"25 mm Lens\", \"blurb\": \"Long-range observation and stand-off detection — the tighter field magnifies distant heat signatures for earlier detection and identification.\", \"specs\": [{\"label\": \"Focal\", \"value\": \"25 mm\"}, {\"label\": \"Aperture\", \"value\": \"F/1.0\"}, {\"label\": \"FOV\", \"value\": \"17.5° × 13°\"}, {\"label\": \"Focus\", \"value\": \"Fixed ∞\"}, {\"label\": \"Material\", \"value\": \"Germanium\"}], \"subtitle\": \"Narrow · 17.5° × 13°\"}], \"heading\": \"Interchangeable Thermal Optics\", \"footnote\": \"Both lenses mount on the same 640×480 · 12 µm core and share the fixed-infinity, deploy-and-go setup. FOV figures are computed for that detector.\"}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(4,15,2,'edgeToEdgeOptics','{\"images\": [{\"alt\": \"ThermIX edge-to-edge thermal sharpness test image\", \"url\": \"/img/products/ThermIX/edge-center.png\", \"note\": \"Every signature locked — corners and center.\", \"caption\": \"AAD ThermIX · Edge-to-Edge\", \"variant\": \"center\"}, {\"alt\": \"Typical thermal lens center-only sharpness sample\", \"url\": \"/img/products/ThermIX/edge-typical.png\", \"note\": \"Edges soften — targets missed at the corners.\", \"caption\": \"Typical Lens · Center Only\", \"variant\": \"typical\"}], \"heading\": \"Edge-to-Edge Optics\", \"oneLine\": \"A heat signature the AI can\'t resolve is a target it can\'t engage — so we don\'t cut corners on the glass.\", \"paragraphs\": [\"Most low-cost thermal lenses are only sharp in the center of the frame. Toward the edges the thermal image softens, and detection models start to miss or misclassify heat signatures that drift away from the middle of the picture.\", \"ThermIX uses a high-quality Germanium lens that holds a uniform, sharp thermal image across the entire frame. Targets are detected and identified just as reliably at the edges as they are dead-center — which matters most in the seconds before a target leaves the field of view.\"]}','2026-07-21 13:02:56','2026-07-21 13:02:56'),(5,15,3,'wieldAiIntegration','{\"cta\": {\"link\": \"/ai-solutions\", \"label\": \"Explore Vanta-AI →\"}, \"lead\": \"ThermIX isn\'t a thermal camera that happens to feed an AI — it\'s built for ours. Vanta-AI runs detection and identification on the live thermal video, drawing a box and a confidence score around every heat signature the model recognises.\", \"image\": {\"alt\": \"Live Vanta-AI detection overlay on the ThermIX thermal video feed\", \"url\": \"/img/products/ThermIX/vanta-ai.png\", \"caption\": \"Live Vanta-AI detections on the ThermIX thermal feed — class label and confidence per target.\"}, \"heading\": \"Tuned for Our Models\", \"features\": [{\"body\": \"We can provide a representative thermal dataset — and a fully trained model — so you can validate detection and identification before you commit.\", \"title\": \"Test Dataset on Request\"}, {\"body\": \"We set the thermal tonemapping, NUC and palette ourselves, calibrated to the conditions our models are trained on — not a generic factory profile.\", \"title\": \"In-House Tuning, NUC & Palettes\"}, {\"body\": \"Because we build both, sensor output and model expectations line up — stronger detection and fewer missed targets out of the box.\", \"title\": \"Camera & Model, Matched\"}]}','2026-07-21 13:02:56','2026-07-21 13:02:56');
/*!40000 ALTER TABLE `product_sections` ENABLE KEYS */;
UNLOCK TABLES;
DROP TABLE IF EXISTS `product_specs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `product_specs` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `product_id` bigint unsigned NOT NULL,
  `spec_group` varchar(64) NOT NULL COMMENT 'Discriminator; accepted values currently: specification, connection_interface. Not an ENUM since more groups may appear later.',
  `spec_name` varchar(255) NOT NULL,
  `spec_value` varchar(500) NOT NULL,
  `sort_order` int unsigned NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `idx_product_specs_product_id` (`product_id`),
  KEY `idx_product_specs_product_id_spec_group` (`product_id`,`spec_group`),
  CONSTRAINT `fk_product_specs_product` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=226 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `product_specs` WRITE;
