CREATE TABLE `products` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `category_id` bigint unsigned NOT NULL,
  `sku` varchar(64) NOT NULL,
  `sku_descriptor` varchar(255) DEFAULT NULL,
  `name` varchar(255) NOT NULL,
  `slug` varchar(255) NOT NULL,
  `subtitle` varchar(255) DEFAULT NULL,
  `short_description` varchar(500) DEFAULT NULL,
  `long_description` text,
  `key_advantage` varchar(500) DEFAULT NULL,
  `package_contents` text,
  `highlights_intro` varchar(500) DEFAULT NULL,
  `specs_intro` varchar(500) DEFAULT NULL,
  `built_for_intro` varchar(500) DEFAULT NULL,
  `compatible_intro` varchar(500) DEFAULT NULL,
  `kb_banner_image` varchar(500) DEFAULT NULL,
  `hero_interfaces` json DEFAULT NULL,
  `documentation_url` varchar(500) DEFAULT NULL,
  `is_ndaa_compliant` tinyint(1) NOT NULL DEFAULT '0',
  `is_made_in_usa` tinyint(1) NOT NULL DEFAULT '0',
  `price` decimal(12,2) DEFAULT NULL,
  `currency` char(3) NOT NULL DEFAULT 'USD',
  `stock_quantity` int unsigned DEFAULT NULL,
  `status` enum('draft','published','archived') NOT NULL DEFAULT 'draft',
  `sort_order` int unsigned NOT NULL DEFAULT '0',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
