INSERT INTO `products` VALUES (1,3,'AAD-FC-7','H7-Basic V3 (8S)','SkyModule X1','skymodule-x1','7','The flagship autopilot of the AAD stack — STM32H743 with full ArduPilot support, triple-IMU redundancy, dual-payload control, and industrial output protection. Built to keep flying in GPS-denied, EW-contested airspace.',NULL,'Keeps flying when comms and GPS are gone — triple sensor redundancy and compass-guided return without yawing the copter, for EW-contested airspace.','1× H7-Basic V3 · 1× USB & Buzzer board · 4× damper grommets · JST-GH 1.25 mm cable set (3/4/5/6/7/8-pin).','Core specs and the combat-grade features that set SkyModule X1 apart.','Complete technical data, connection interfaces, and package contents (H7-Basic V3 board).','A versatile autopilot across every platform ArduPilot supports — from FPV strike drones to fixed-wing ISR.','Built to work as one system on the AAD CAN-bus stack.','/img/products/skymodule-x1/kb-banner.png',NULL,NULL,1,1,NULL,'USD',NULL,'published',1,'2026-07-21 13:02:54','2026-07-21 13:02:55'),(2,3,'AAD-FC-7L','H7-Lite','SkyModule X1-Lite','skymodule-x1-lite','7L','A compact autopilot for weight-sensitive platforms on STM32H743 — dual IMU, native digital FPV output and a dedicated gimbal port, with built-in interfaces for 4-in-1 ESC and CAN peripherals.',NULL,'FC7-class resilience in a compact footprint — built-in gimbal and 4-in-1 ESC ports remove adapter modules that add weight and failure points.','1× H7-Lite board · JST GH-1.25 mm cable set · ArduPilot firmware 4.5.5 and 4.6.3 with H7-Lite Defines · 3D models for the board and USB adapter.','Core specs and the compact-build features that set SkyModule X1-Lite apart.','Complete technical data, connection interfaces, and package contents (H7-Lite board).','A compact autopilot for weight-sensitive airframes — from FPV strike drones to gimbal-camera platforms.','Built to work as one system on the AAD CAN-bus stack.','/img/products/skymodule-x1-lite/kb-banner.png',NULL,NULL,1,1,NULL,'USD',NULL,'published',2,'2026-07-21 13:02:54','2026-07-21 13:02:55'),(3,4,'AAD-ComputeNode-AI','Drone Pi motherboard','ComputeNode Z','computenode-z','AI','A field-swappable onboard compute module built on Raspberry Pi CM4 or CM5, with an optional Hailo accelerator delivering up to 26 TOPS of onboard inference and direct CAN access to SkyModule X1. Powered straight off the airframe bus.',NULL,'Field-swappable compute module with a dedicated AI accelerator — up to 26 TOPS of onboard inference without redesigning the airframe, and direct CAN access to SkyModule X1 with no adapters.','1× Drone Pi motherboard. Exact Hailo module, OS image and software stack, cooling and first-setup guide — see the Knowledge Base.','Core specs and the onboard-AI features that set ComputeNode Z apart.','Complete technical data, connection interfaces, and package contents (Drone Pi motherboard).','Onboard compute for tactical UAS that fuse cameras, AI inference and flight control on the airframe.','Built to work as one system on the AAD CAN-bus stack.','/img/products/computenode-z/kb-banner.png',NULL,NULL,1,1,NULL,'USD',NULL,'published',3,'2026-07-21 13:02:54','2026-07-21 13:02:55'),(4,5,'AAD-GeoNav-DB','Dual-Band GNSS v2','GeoNav Dual','geonav-dual','DB','Dual-band GNSS module (L1+L5) built on the LOCOSYS MC1010-V2a, with hardware spoofing protection, a passive ceramic antenna and a built-in compass. Engineered to hold position in EW-contested airspace.',NULL,'Hardware-level anti-spoofing — simultaneous L1+L5 reception detects spoofing, and a relay physically cuts GPS power on detection so false coordinates never reach the flight stack.','1× GNSS module · 1× passive ceramic antenna (50×50×10 mm) · GNSS & I2C compass cables.','Core specs and the anti-spoofing features that set GeoNav Dual apart.','Complete technical data, connection interfaces, and package contents (Dual-Band GNSS v2).','Spoofing-resistant navigation across every platform on the AAD stack — from EW-contested ISR to long-range strike.','Built to work as one system on the AAD CAN-bus stack.','/img/products/geonav-dual/kb-banner.png',NULL,NULL,1,1,NULL,'USD',NULL,'published',4,'2026-07-21 13:02:54','2026-07-21 13:02:55'),(5,6,'AAD-FieldSense','RM3100','FieldSense','fieldsense',NULL,'A high-precision external compass built on the industrial RM3100 sensor (PNI Sensor, USA), connected over I²C. Isolated coils hold a clear heading even on high-current multirotors, and the compact module mounts away from motor and ESC interference for a clean magnetic reference.',NULL,'Industrial-grade RM3100 with isolated coils — high noise immunity and a clear heading even on multirotors where motors defeat other magnetometers.','1× FieldSense (I²C) module with RM3100 sensor.','Core specs and the precision-sensing features that set FieldSense apart.','Complete technical data, connection interfaces, and package contents (FieldSense I²C variant).','An external compass for platforms that need a clean magnetic heading. For a CAN bus connection, see FieldSense CAN.','Built to work as one system on the AAD stack.','/img/products/fieldsense/kb-banner.png',NULL,NULL,1,1,NULL,'USD',NULL,'published',5,'2026-07-21 13:02:54','2026-07-21 13:02:55'),(6,6,'AAD-FieldSense-CAN','RM3100','FieldSense CAN','fieldsense-can','CAN','A high-precision RM3100 compass on the CAN bus. It daisy-chains straight onto the AAD CAN backbone over a single cable and mounts clear of motor and ESC EMI — for a clear heading even on high-current multirotors where other magnetometers lose the plot.',NULL,'Industrial-grade RM3100 with isolated coils — high noise immunity and a clear heading even on multirotors where motors defeat other magnetometers.','1× FieldSense CAN module · CAN daisy-chain cabling.','Core specs and the combat-grade features that set FieldSense CAN apart.','Complete technical data, connection interfaces, and package contents (FieldSense CAN variant).','An external compass for noisy, contested platforms — wherever a clean heading on the CAN bus matters most.','Built to work as one system on the AAD CAN-bus stack.','/img/products/fieldsense-can/kb-banner.png',NULL,NULL,1,1,NULL,'USD',NULL,'published',6,'2026-07-21 13:02:54','2026-07-21 13:02:55'),(7,6,'AAD-AirFlow-CAN','CAN Airspeed module','AirFlow CAN','airflow-can','CAN','A digital CAN airspeed sensor for fixed-wing and VTOL UAVs — immune to electromagnetic noise from the power system. It feeds the autopilot clean airspeed data to prevent critical stalls and hold flight efficiency, where analog sensors are swamped by noise.',NULL,'A digital CAN interface immune to electromagnetic noise from UAV power systems — reliable airspeed data where analog sensors are swamped by noise.','1× AirFlow CAN module · 1× pitot tube · 1× heating module · CAN cabling.','Core specs and the features that set AirFlow CAN apart on the airframe.','Complete technical data, connection interfaces, and package contents.','Airframes where reliable airspeed is mission-critical — from high-speed strike to long-endurance recon.','Built to work as one system on the AAD CAN-bus stack.','/img/products/airflow-can/kb-banner.png',NULL,NULL,1,1,NULL,'USD',NULL,'published',7,'2026-07-21 13:02:54','2026-07-21 13:02:55'),(8,6,'AAD-MultiSense','Module CAN SENS','MultiSense','multisense',NULL,'One CAN sensor hub — six factory configurations combining GNSS, compass, airspeed, and barometer in a single module. Critical flight and navigation sensors integrated on one board, streaming data to the controller over CAN.',NULL,'Four sensors worth of capability in one CAN module — fewer parts to source, wire and certify, and faster integration.','1× MultiSense module (selected configuration) · CAN cable set.','Core specs and the integration advantages that set MultiSense apart.','Complete technical data, connection interface, and package contents.','A consolidated sensor hub for platforms that demand reliable navigation with minimal wiring.','Built to work as one system on the AAD CAN-bus stack.','/img/products/multisense/kb-banner.png',NULL,NULL,1,1,NULL,'USD',0,'published',8,'2026-07-21 13:02:54','2026-07-21 15:09:25'),(9,7,'AAD-PMU-16S',NULL,'CAN PMU 16S','can-pmu-16s','16S','High-current 16S power module for current measurement and power to the controller, peripherals and ESC — with full DroneCAN telemetry and ESC control over the CAN bus. Built for heavy-lift platforms drawing up to 200 A continuous.',NULL,'Current measurement, power for controller and peripherals, ESC control and power — all on the CAN bus, with short-circuit protection on the regulated lines.','1× CAN PMU 16S 200A module. See the Knowledge Base for the full package contents diagram.','Core specs and the high-current features that set the CAN PMU 16S apart.','Complete technical data, connection interfaces, and package contents for the CAN PMU 16S 200A.','A high-current power module for the most demanding airframes — wherever sustained 200 A draw and CAN-bus telemetry are required.','Built to work as one system on the AAD CAN-bus stack.','/img/products/can-pmu-16s/kb-banner.png',NULL,NULL,1,1,NULL,'USD',NULL,'published',9,'2026-07-21 13:02:54','2026-07-21 13:02:55'),(10,7,'AAD-PMU-L14S','CAN PMU Lite 14S','CAN PMU Lite 14S','can-pmu-lite-14s','L14S','Lighter CAN power monitoring and ESC control for mid-size platforms. Measures battery voltage and current, powers the controller and peripherals, and drives the ESC — all over the DroneCAN bus, with short-circuit protection on the regulated lines.',NULL,'Current measurement, power for controller and peripherals, ESC control and power — all on the CAN bus, with short-circuit protection on the regulated lines.','CAN PMU Lite 14S module with connection cabling — see the Knowledge Base for the full package list.','Core specs and the field-proven features that define the CAN PMU Lite 14S.','Complete technical data, connection interfaces, and package contents (CAN PMU Lite 14S).','Lighter CAN power and ESC control sized for mid-size platforms.','Built to work as one system on the AAD CAN-bus stack.','/img/products/can-pmu-lite-14s/kb-banner.png',NULL,NULL,1,1,NULL,'USD',NULL,'published',10,'2026-07-21 13:02:54','2026-07-21 13:02:55'),(11,7,'AAD-POWERCORE-EX',NULL,'PowerCore EX','powercore-ex','EX','An H7 expansion board that stacks directly on SkyModule X1 — adding accurate current sensing and a 6-channel servo rail. Selectable 5V/8V output makes it a universal solution for standard and high-voltage servos.',NULL,'Stacks directly on SkyModule X1 (matching 30.5×30.5 mm) — adds accurate current sensing and a 6-channel 5V/8V servo rail with no separate board stack or cable runs.','1× PowerCore EX board · XT60 connector · pre-installed servo header strip · 22-pin FFC 0.5 mm ribbon to FC.','Core specs and the integration features that set PowerCore EX apart.','Complete technical data, connection interfaces, and package contents.','Purpose-built to expand the SkyModule X1 stack with sensing and servo power for demanding airframes.','Built to work as one system on the AAD stack.','/img/products/powercore-ex/kb-banner.png',NULL,NULL,1,1,NULL,'USD',NULL,'published',11,'2026-07-21 13:02:54','2026-07-21 13:02:55'),(12,7,'AAD-POWERRAIL-14S','Servo Rail with BEC','PowerRail 14S','powerrail-14s','14S','A servo distribution rail with a high-current BEC and protected outputs. Carries up to 12 PWM signals straight from a 4–14S battery and can switch into an ESC-telemetry mode on outputs 1–4.',NULL,'Up to 12 PWM channels with a high-current BEC straight from 4–14S — plus an ESC-telemetry mode on outputs 1–4 when used with H7-Basic.','1× PowerRail 14S · 1× JST-GH 1.25 mm 14-pin cable · mounting standoffs.','Core specs and the combat-grade features that set PowerRail 14S apart.','Complete technical data, connection interfaces, and package contents.','A dedicated servo rail for airframes that demand many actuators and clean, protected power.','Built to work as one system on the AAD CAN-bus stack.','/img/products/powerrail-14s/kb-banner.png',NULL,NULL,1,1,NULL,'USD',NULL,'published',12,'2026-07-21 13:02:54','2026-07-21 13:02:55'),(13,7,'AAD-SERVONODE-X4','CAN SRV x4E','ServoNode x4','servonode-x4','X4','A CAN-connected node that powers and controls servos and ESCs over the bus — isolating the load from the flight controller. Four independent PWM outputs plus a separate ESC control output with telemetry, immune to EM noise and ready to expand the controller\'s PWM channel count.',NULL,'Powers and controls servos and ESCs over CAN — the load is isolated from the controller, immune to EM noise, plus PWM output expansion.','1× ServoNode x4 node. Full box contents are detailed in the Knowledge Base.','Core specs and the CAN-bus advantages that set ServoNode x4 apart.','Complete technical data, connection interfaces, and package contents.','Airframes that distribute actuation across the CAN bus and run out of controller PWM channels.','Built to work as one system on the AAD CAN-bus stack.','/img/products/servonode-x4/kb-banner.png',NULL,NULL,1,1,NULL,'USD',NULL,'published',13,'2026-07-21 13:02:54','2026-07-21 13:02:55'),(14,8,'AAD-CAM-Optix','STARVIS 2 Clear HDR','Optix-D','Optix-d',NULL,'A compact 2.4 MP STARVIS 2 day camera with Clear HDR and a video pipeline built to be read by an onboard detection model. One camera, two interface variants — choose native digital Ethernet or a direct MIPI CSI-2 link to your compute module. Removable IR-cut filter for low-light work.',NULL,'STARVIS 2 + Clear HDR for dawn, dusk, fog and high-contrast urban scenes — ultra-low latency video output, built to be read by an onboard detection model.',NULL,'Core specs and the features that make Optix-D the daylight eye of the AAD targeting stack.','Shared optical and electrical specs, with interface-specific notes for the two output options — digital Ethernet and MIPI CSI-2.','A daylight sensor tuned for real-time guidance and onboard AI across strike, ISR and gimbal platforms.','Built to work as one system — camera, compute and AI on a single digital stack.',NULL,'[{\"sub\": \"UDP/RTSP H.264/H.265 · <50 ms\", \"title\": \"Digital Ethernet\"}, {\"sub\": \"Direct-to-SoC · uncompressed · <10 ms\", \"title\": \"MIPI CSI-2\"}]',NULL,1,1,NULL,'USD',NULL,'published',1,'2026-07-21 13:02:55','2026-07-21 13:02:56'),(15,8,'AAD-CAM-ThermIX','640 VOx core','ThermIX','ThermIX',NULL,'An uncooled LWIR thermal camera that sees through total darkness, smoke and degraded visibility. One camera, two interface variants — digital Ethernet for onboard AI, or analog CVBS plus digital USB UVC for legacy FPV chains — on a 640×480 VOx core, with interchangeable Germanium optics.',NULL,'A high-sensitivity 12 µm VOx core (NETD < 15 mK) for detection in complete darkness, smoke and degraded visibility — clean thermal frames built to be read by an onboard detection model, with a choice of 9 mm or 25 mm optics.',NULL,'Core specs and the features that make ThermIX the all-conditions thermal eye of the AAD targeting stack.','Shared thermal-core specs, with interface-specific notes for the two output variants — digital Ethernet (ThermIX-D) and analog CVBS (ThermIX-A).','A thermal sensor for the missions daylight can\'t reach — night, smoke and degraded visibility, across strike and ISR platforms.','Built to work as one system — camera, compute and AI on a single stack.',NULL,'[{\"sub\": \"UDP/RTSP H.264/H.265 · <50 ms\", \"title\": \"Digital Ethernet · ThermIX-D\"}, {\"sub\": \"CVBS analog + USB UVC · 30 ms\", \"title\": \"Analog + USB · ThermIX-A\"}]',NULL,1,1,NULL,'USD',NULL,'published',2,'2026-07-21 13:02:55','2026-07-21 13:02:56');
