DROP TABLE IF EXISTS `urls`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `urls` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `category_id` bigint unsigned DEFAULT NULL,
  `product_id` bigint unsigned DEFAULT NULL,
  `link` varchar(255) NOT NULL,
  `canonical` varchar(500) DEFAULT NULL,
  `meta_title` varchar(255) DEFAULT NULL,
  `meta_description` varchar(500) DEFAULT NULL,
  `og_title` varchar(255) DEFAULT NULL,
  `og_description` varchar(500) DEFAULT NULL,
  `og_image` varchar(500) DEFAULT NULL,
  `is_indexable` tinyint(1) NOT NULL DEFAULT '1',
  `routes` varchar(255) DEFAULT NULL,
  `view` varchar(255) DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_urls_link` (`link`),
  UNIQUE KEY `uq_urls_category_id` (`category_id`),
  UNIQUE KEY `uq_urls_product_id` (`product_id`),
  CONSTRAINT `fk_urls_category` FOREIGN KEY (`category_id`) REFERENCES `categories` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `fk_urls_product` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `ck_urls_xor_page` CHECK (((`category_id` is null) <> (`product_id` is null)))
) ENGINE=InnoDB AUTO_INCREMENT=24 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='Per-page SEO/routing metadata; each row belongs to exactly one category XOR one product (ck_urls_xor_page); uq_urls_category_id/uq_urls_product_id enforce at most one urls row per page (multiple NULLs allowed under UNIQUE).';
/*!40101 SET character_set_client = @saved_cs_client */;

LOCK TABLES `urls` WRITE;
