ULL,NULL,NULL,1,NULL,NULL,'2026-07-21 13:02:54','2026-07-21 13:02:55'),(11,NULL,4,'drone-components/electronics/gnss-navigation/geonav-dual','/drone-components/electronics/gnss-navigation/geonav-dual',NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,'2026-07-21 13:02:54','2026-07-21 13:02:54'),(12,NULL,5,'drone-components/electronics/sensors/fieldsense','/drone-components/electronics/sensors/fieldsense',NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,'2026-07-21 13:02:54','2026-07-21 13:02:54'),(13,NULL,6,'drone-components/electronics/sensors/fieldsense-can','/drone-components/electronics/sensors/fieldsense-can',NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,'2026-07-21 13:02:54','2026-07-21 13:02:54'),(14,NULL,7,'drone-components/electronics/sensors/airflow-can','/drone-components/electronics/sensors/airflow-can',NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,'2026-07-21 13:02:54','2026-07-21 13:02:54'),(15,NULL,8,'drone-components/electronics/sensors/multisense','/drone-components/electronics/sensors/multisense',NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,'2026-07-21 13:02:54','2026-07-21 13:02:54'),(16,NULL,9,'drone-components/electronics/power-servo/can-pmu-16s','/drone-components/electronics/power-servo/can-pmu-16s',NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,'2026-07-21 13:02:54','2026-07-21 13:02:54'),(17,NULL,10,'drone-components/electronics/power-servo/can-pmu-lite-14s','/drone-components/electronics/power-servo/can-pmu-lite-14s',NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,'2026-07-21 13:02:54','2026-07-21 13:02:54'),(18,NULL,11,'drone-components/electronics/power-servo/powercore-ex','/drone-components/electronics/power-servo/powercore-ex',NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,'2026-07-21 13:02:54','2026-07-21 13:02:54'),(19,NULL,12,'drone-components/electronics/power-servo/powerrail-14s','/drone-components/electronics/power-servo/powerrail-14s',NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,'2026-07-21 13:02:54','2026-07-21 13:02:54'),(20,NULL,13,'drone-components/electronics/power-servo/servonode-x4','/drone-components/electronics/power-servo/servonode-x4',NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,'2026-07-21 13:02:54','2026-07-21 13:02:54'),(21,8,NULL,'cameras','/cameras',NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(22,NULL,14,'drone-components/cameras/Optix-d','/drone-components/cameras/Optix-d',NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,'2026-07-21 13:02:55','2026-07-21 13:02:55'),(23,NULL,15,'drone-components/cameras/ThermIX','/drone-components/cameras/ThermIX',NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,'2026-07-21 13:02:55','2026-07-21 13:02:55');
